import { useEffect, useState } from 'react';

export function useAsyncMemo<T>(
    fn: () => Promise<T>,
    deps: any[],
    initialValue: T = undefined,
): T {
    const [value, setValue] = useState<T>(initialValue);
    useEffect(() => {
        let cancelled = false;
        fn().then(result => {
            if (!cancelled) {
                setValue(result);
            }
        });
        return () => { cancelled = true; };
    }, deps);
    return value;
}
EOF

