43: export default abstract class HeaderButtons<P = {}> extends React.Component<IProps & P, IState> {
44:     private unmounted = false;
45:     private dispatcherRef: string;
46: 
47:     constructor(props: IProps & P, kind: HeaderKind) {
48:         super(props);
49: 
50:         const rps = RightPanelStore.instance;
51:         this.state = {
52:             headerKind: kind,
53:             phase: rps.currentCard.phase,
54:             threadNotificationColor: NotificationColor.None,
55:             globalNotificationColor: NotificationColor.None,
56:         };
57:     }
