59:     public componentDidMount() {
60:         RightPanelStore.instance.on(UPDATE_EVENT, this.onRightPanelStoreUpdate);
61:         this.dispatcherRef = dis.register(this.onAction.bind(this)); // used by subclasses
62:     }
