24: import { Icon as ContextMenuIcon } from '../../../../res/img/element-icons/context-menu.svg';
25: import { Icon as EmojiIcon } from "../../../../res/img/element-icons/room/message-bar/emoji.svg";
26: import { Icon as ReplyIcon } from '../../../../res/img/element-icons/room/message-bar/reply.svg';
27: import { _t } from "../../../languageHandler";
28: import BaseCard from "./BaseCard";
29: import Spinner from "../elements/Spinner";
30: import MatrixClientContext from "../../../contexts/MatrixClientContext";
31: import { useTypedEventEmitter } from "../../../hooks/useEventEmitter";
32: import PinningUtils from "../../../utils/PinningUtils";
33: import { useAsyncMemo } from "../../../hooks/useAsyncMemo";
34: import PinnedEventTile from "../rooms/PinnedEventTile";
35: import { useRoomState } from "../../../hooks/useRoomState";
36: import RoomContext, { TimelineRenderingType } from "../../../contexts/RoomContext";
37: import { ReadPinsEventId } from "./types";
38: import Heading from '../typography/Heading';
39: import { RoomPermalinkCreator } from "../../../utils/permalinks/Permalinks";
40: 
41: interface IProps {
42:     room: Room;
43:     permalinkCreator: RoomPermalinkCreator;
44:     onClose(): void;
45: }
46: 
47: export const usePinnedEvents = (room: Room): string[] => {
48:     const [pinnedEvents, setPinnedEvents] = useState<string[]>([]);
49: 
50:     const update = useCallback((ev?: MatrixEvent) => {
51:         if (!room) return;
52:         if (ev && ev.getType() !== EventType.RoomPinnedEvents) return;
53:         setPinnedEvents(room.currentState.getStateEvents(EventType.RoomPinnedEvents, "")?.getContent()?.pinned || []);
54:     }, [room]);
55: 
56:     useTypedEventEmitter(room?.currentState, RoomStateEvent.Events, update);
57:     useEffect(() => {
58:         update();
59:         return () => {
60:             setPinnedEvents([]);
61:         };
62:     }, [update]);
63:     return pinnedEvents;
64: };
65: 
66: export const useReadPinnedEvents = (room: Room): Set<string> => {
67:     const [readPinnedEvents, setReadPinnedEvents] = useState<Set<string>>(new Set());
68: 
69:     const update = useCallback((ev?: MatrixEvent) => {
70:         if (!room) return;
71:         if (ev && ev.getType() !== ReadPinsEventId) return;
72:         const readPins = room.getAccountData(ReadPinsEventId)?.getContent()?.event_ids;
73:         setReadPinnedEvents(new Set(readPins || []));
74:     }, [room]);
75: 
76:     useTypedEventEmitter(room, RoomEvent.AccountData, update);
77:     useEffect(() => {
78:         update();
79:         return () => {
80:             setReadPinnedEvents(new Set());
81:         };
82:     }, [update]);
83:     return readPinnedEvents;
84: };
85: 
86: const PinnedMessagesCard = ({ room, onClose, permalinkCreator }: IProps) => {
87:     const cli = useContext(MatrixClientContext);
88:     const roomContext = useContext(RoomContext);
89:     const canUnpin = useRoomState(room, state => state.mayClientSendStateEvent(EventType.RoomPinnedEvents, cli));
90:     const pinnedEventIds = usePinnedEvents(room);
91:     const readPinnedEvents = useReadPinnedEvents(room);
92: 
93:     useEffect(() => {
94:         const newlyRead = pinnedEventIds.filter(id => !readPinnedEvents.has(id));
95:         if (newlyRead.length > 0) {
96:             // clear out any read pinned events which no longer are pinned
97:             cli.setRoomAccountData(room.roomId, ReadPinsEventId, {
98:                 event_ids: pinnedEventIds,
99:             });
100:         }
101:     }, [cli, room.roomId, pinnedEventIds, readPinnedEvents]);
102: 
103:     const pinnedEvents = useAsyncMemo(() => {
104:         const promises = pinnedEventIds.map(async eventId => {
105:             const timelineSet = room.getUnfilteredTimelineSet();
106:             const localEvent = timelineSet?.getTimelineForEvent(eventId)?.getEvents().find(e => e.getId() === eventId);
107:             if (localEvent) return PinningUtils.isPinnable(localEvent) ? localEvent : null;
108: 
109:             try {
110:                 // Fetch the event and latest edit in parallel
111:                 const [evJson, { events: [edit] }] = await Promise.all([
112:                     cli.fetchRoomEvent(room.roomId, eventId),
113:                     cli.relations(room.roomId, eventId, RelationType.Replace, null, { limit: 1 }),
114:                 ]);
115:                 const event = new MatrixEvent(evJson);
116:                 if (event.isEncrypted()) {
117:                     await cli.decryptEventIfNeeded(event); // TODO await?
118:                 }
119: 
120:                 if (event && PinningUtils.isPinnable(event)) {
121:                     // Inject sender information
122:                     event.sender = room.getMember(event.getSender());
123:                     // Also inject any edits we've found
124:                     if (edit) event.makeReplaced(edit);
125: 
126:                     return event;
127:                 }
128:             } catch (err) {
129:                 logger.error("Error looking up pinned event " + eventId + " in room " + room.roomId);
130:                 logger.error(err);
131:             }
132:             return null;
133:         });
134: 
135:         return Promise.all(promises);
136:     }, [cli, room, pinnedEventIds], null);
137: 
138:     let content;
139:     if (!pinnedEvents) {
140:         content = <Spinner />;
141:     } else if (pinnedEvents.length > 0) {
142:         const onUnpinClicked = async (event: MatrixEvent) => {
143:             const pinnedEvents = room.currentState.getStateEvents(EventType.RoomPinnedEvents, "");
144:             if (pinnedEvents?.getContent()?.pinned) {
145:                 const pinned = pinnedEvents.getContent().pinned;
146:                 const index = pinned.indexOf(event.getId());
147:                 if (index !== -1) {
148:                     pinned.splice(index, 1);
149:                     await cli.sendStateEvent(room.roomId, EventType.RoomPinnedEvents, { pinned }, "");
150:                 }
151:             }
152:         };
153: 
154:         // show them in reverse, with latest pinned at the top
155:         content = pinnedEvents.filter(Boolean).reverse().map(ev => (
156:             <PinnedEventTile
157:                 key={ev.getId()}
158:                 event={ev}
159:                 onUnpinClicked={canUnpin ? () => onUnpinClicked(ev) : undefined}
160:                 permalinkCreator={permalinkCreator}
161:             />
162:         ));
163:     } else {
164:         content = <div className="mx_PinnedMessagesCard_empty_wrapper">
165:             <div className="mx_PinnedMessagesCard_empty">
166:                 { /* XXX: We reuse the classes for simplicity, but deliberately not the components for non-interactivity. */ }
167:                 <div className="mx_MessageActionBar mx_PinnedMessagesCard_MessageActionBar">
168:                     <div className="mx_MessageActionBar_iconButton">
169:                         <EmojiIcon />
170:                     </div>
171:                     <div className="mx_MessageActionBar_iconButton">
172:                         <ReplyIcon />
173:                     </div>
174:                     <div className="mx_MessageActionBar_iconButton mx_MessageActionBar_optionsButton">
175:                         <ContextMenuIcon />
176:                     </div>
177:                 </div>
178: 
179:                 <Heading size="h4" className="mx_PinnedMessagesCard_empty_header">{ _t("Nothing pinned, yet") }</Heading>
180:                 { _t("If you have permissions, open the menu on any message and select " +
181:                     "<b>Pin</b> to stick them here.", {}, {
182:                     b: sub => <b>{ sub }</b>,
183:                 }) }
184:             </div>
185:         </div>;
186:     }
187: 
188:     return <BaseCard
189:         header={<div className="mx_BaseCard_header_title">
190:             <Heading size="h4" className="mx_BaseCard_header_title_heading">{ _t("Pinned messages") }</Heading>
191:         </div>}
192:         className="mx_PinnedMessagesCard"
193:         onClose={onClose}
194:     >
195:         <RoomContext.Provider value={{
196:             ...roomContext,
197:             timelineRenderingType: TimelineRenderingType.Pinned,
198:         }}>
199:             { content }
200:         </RoomContext.Provider>
201:     </BaseCard>;
202: };
203: 
204: export default PinnedMessagesCard;
