80: /**
81:  * to improve screen reader experience translations that are not in the main page language
82:  * eg a translation that fell back to english from another language
83:  * should be wrapped with an appropriate `lang='en'` attribute
84:  * counterpart's `translate` doesn't expose a way to determine if the resulting translation
85:  * is in the target locale or a fallback locale
86:  * for this reason, force fallbackLocale === locale in the first call to translate
87:  * and fallback 'manually' so we can mark fallback strings appropriately
88:  * */
89: const translateWithFallback = (text: string, options?: object): { translated?: string, isFallback?: boolean } => {
90:     const translated = counterpart.translate(text, { ...options, fallbackLocale: counterpart.getLocale() });
91:     if (!translated || translated.startsWith("missing translation:")) {
92:         const fallbackTranslated = counterpart.translate(text, { ...options, locale: FALLBACK_LOCALE });
93:         if ((!fallbackTranslated || fallbackTranslated.startsWith("missing translation:"))
94:             && process.env.NODE_ENV !== "development") {
95:             // Even the translation via FALLBACK_LOCALE failed; this can happen if
96:             //
97:             // 1. The string isn't in the translations dictionary, usually because you're in develop
98:             // and haven't run yarn i18n
99:             // 2. Loading the translation resources over the network failed, which can happen due to
100:             // to network or if the client tried to load a translation that's been removed from the
101:             // server.
102:             //
103:             // At this point, its the lesser evil to show the untranslated text, which
104:             // will be in English, so the user can still make out *something*, rather than an opaque
105:             // "missing translation" error.
106:             //
107:             // Don't do this in develop so people remember to run yarn i18n.
108:             return { translated: text, isFallback: true };
109:         }
110:         return { translated: fallbackTranslated, isFallback: true };
111:     }
112:     return { translated };
113: };
