115: // Wrapper for counterpart's translation function so that it handles nulls and undefineds properly
116: // Takes the same arguments as counterpart.translate()
117: function safeCounterpartTranslate(text: string, variables?: object) {
118:     // Don't do substitutions in counterpart. We handle it ourselves so we can replace with React components
119:     // However, still pass the variables to counterpart so that it can choose the correct plural if count is given
120:     // It is enough to pass the count variable, but in the future counterpart might make use of other information too
121:     const options = { ...variables, interpolate: false };
122: 
123:     // Horrible hack to avoid https://github.com/vector-im/element-web/issues/4191
124:     // The interpolation library that counterpart uses does not support undefined/null
125:     // values and instead will throw an error. This is a problem since everywhere else
126:     // in JS land passing undefined/null will simply stringify instead, and when converting
127:     // valid ES6 template strings to i18n strings it's extremely easy to pass undefined/null
128:     // if there are no existing null guards. To avoid this making the app completely inoperable,
129:     // we'll check all the values for undefined/null and stringify them here.
130:     if (options && typeof options === 'object') {
131:         Object.keys(options).forEach((k) => {
132:             if (options[k] === undefined) {
133:                 logger.warn("safeCounterpartTranslate called with undefined interpolation name: " + k);
134:                 options[k] = 'undefined';
135:             }
136:             if (options[k] === null) {
137:                 logger.warn("safeCounterpartTranslate called with null interpolation name: " + k);
138:                 options[k] = 'null';
139:             }
140:         });
141:     }
142:     return translateWithFallback(text, options);
143: }
