145: type SubstitutionValue = number | string | React.ReactNode | ((sub: string) => React.ReactNode);
146: 
147: export interface IVariables {
148:     count?: number;
149:     [key: string]: SubstitutionValue;
150: }
151: 
152: export type Tags = Record<string, SubstitutionValue>;
