156: // For development/testing purposes it is useful to also output the original string
157: // Don't do that for release versions
158: const annotateStrings = (result: TranslatedString, translationKey: string): TranslatedString => {
159:     if (!ANNOTATE_STRINGS) {
160:         return result;
161:     }
162: 
163:     if (typeof result === 'string') {
164:         return `@@${translationKey}##${result}@@`;
165:     } else {
166:         return <span className='translated-string' data-orig-string={translationKey}>{ result }</span>;
167:     }
168: };
