170: /*
171:  * Translates text and optionally also replaces XML-ish elements in the text with e.g. React components
172:  * @param {string} text The untranslated text, e.g "click <a>here</a> now to %(foo)s".
173:  * @param {object} variables Variable substitutions, e.g { foo: 'bar' }
174:  * @param {object} tags Tag substitutions e.g. { 'a': (sub) => <a>{sub}</a> }
175:  *
176:  * In both variables and tags, the values to substitute with can be either simple strings, React components,
177:  * or functions that return the value to use in the substitution (e.g. return a React component). In case of
178:  * a tag replacement, the function receives as the argument the text inside the element corresponding to the tag.
179:  *
180:  * Use tag substitutions if you need to translate text between tags (e.g. "<a>Click here!</a>"), otherwise
181:  * you will end up with literal "<a>" in your output, rather than HTML. Note that you can also use variable
182:  * substitution to insert React components, but you can't use it to translate text between tags.
183:  *
184:  * @return a React <span> component if any non-strings were used in substitutions, otherwise a string
185:  */
186: // eslint-next-line @typescript-eslint/naming-convention
187: export function _t(text: string, variables?: IVariables): string;
188: export function _t(text: string, variables: IVariables, tags: Tags): React.ReactNode;
189: export function _t(text: string, variables?: IVariables, tags?: Tags): TranslatedString {
190:     // The translation returns text so there's no XSS vector here (no unsafe HTML, no code execution)
191:     const { translated } = safeCounterpartTranslate(text, variables);
192:     const substituted = substitute(translated, variables, tags);
193: 
194:     return annotateStrings(substituted, text);
195: }
