197: /*
198:  * Wraps normal _t function and adds atttribution for translations that used a fallback locale
199:  * Wraps translations that fell back from active locale to fallback locale with a `<span lang=<fallback locale>>`
200:  * @param {string} text The untranslated text, e.g "click <a>here</a> now to %(foo)s".
201:  * @param {object} variables Variable substitutions, e.g { foo: 'bar' }
202:  * @param {object} tags Tag substitutions e.g. { 'a': (sub) => <a>{sub}</a> }
203:  *
204:  * @return a React <span> component if any non-strings were used in substitutions
205:  * or translation used a fallback locale, otherwise a string
206:  */
207: // eslint-next-line @typescript-eslint/naming-convention
208: export function _tDom(text: string, variables?: IVariables): TranslatedString;
209: export function _tDom(text: string, variables: IVariables, tags: Tags): React.ReactNode;
210: export function _tDom(text: string, variables?: IVariables, tags?: Tags): TranslatedString {
211:     // The translation returns text so there's no XSS vector here (no unsafe HTML, no code execution)
212:     const { translated, isFallback } = safeCounterpartTranslate(text, variables);
213:     const substituted = substitute(translated, variables, tags);
214: 
215:     // wrap en fallback translation with lang attribute for screen readers
216:     const result = isFallback ? <span lang='en'>{ substituted }</span> : substituted;
217: 
218:     return annotateStrings(result, text);
219: }
