221: /**
222:  * Sanitizes unsafe text for the sanitizer, ensuring references to variables will not be considered
223:  * replaceable by the translation functions.
224:  * @param {string} text The text to sanitize.
225:  * @returns {string} The sanitized text.
226:  */
227: export function sanitizeForTranslation(text: string): string {
228:     // Add a non-breaking space so the regex doesn't trigger when translating.
229:     return text.replace(/%\(([^)]*)\)/g, '%\xa0($1)');
230: }
