232: /*
233:  * Similar to _t(), except only does substitutions, and no translation
234:  * @param {string} text The text, e.g "click <a>here</a> now to %(foo)s".
235:  * @param {object} variables Variable substitutions, e.g { foo: 'bar' }
236:  * @param {object} tags Tag substitutions e.g. { 'a': (sub) => <a>{sub}</a> }
237:  *
238:  * The values to substitute with can be either simple strings, or functions that return the value to use in
239:  * the substitution (e.g. return a React component). In case of a tag replacement, the function receives as
240:  * the argument the text inside the element corresponding to the tag.
241:  *
242:  * @return a React <span> component if any non-strings were used in substitutions, otherwise a string
243:  */
244: export function substitute(text: string, variables?: IVariables): string;
245: export function substitute(text: string, variables: IVariables, tags: Tags): string;
246: export function substitute(text: string, variables?: IVariables, tags?: Tags): string | React.ReactNode {
247:     let result: React.ReactNode | string = text;
248: 
249:     if (variables !== undefined) {
250:         const regexpMapping: IVariables = {};
251:         for (const variable in variables) {
252:             regexpMapping[`%\\(${variable}\\)s`] = variables[variable];
253:         }
254:         result = replaceByRegexes(result as string, regexpMapping);
255:     }
256: 
257:     if (tags !== undefined) {
258:         const regexpMapping: Tags = {};
259:         for (const tag in tags) {
260:             regexpMapping[`(<${tag}>(.*?)<\\/${tag}>|<${tag}>|<${tag}\\s*\\/>)`] = tags[tag];
261:         }
262:         result = replaceByRegexes(result as string, regexpMapping);
263:     }
264: 
265:     return result;
266: }
