268: /*
269:  * Replace parts of a text using regular expressions
270:  * @param {string} text The text on which to perform substitutions
271:  * @param {object} mapping A mapping from regular expressions in string form to replacement string or a
272:  * function which will receive as the argument the capture groups defined in the regexp. E.g.
273:  * { 'Hello (.?) World': (sub) => sub.toUpperCase() }
274:  *
275:  * @return a React <span> component if any non-strings were used in substitutions, otherwise a string
276:  */
277: export function replaceByRegexes(text: string, mapping: IVariables): string;
278: export function replaceByRegexes(text: string, mapping: Tags): React.ReactNode;
279: export function replaceByRegexes(text: string, mapping: IVariables | Tags): string | React.ReactNode {
280:     // We initially store our output as an array of strings and objects (e.g. React components).
281:     // This will then be converted to a string or a <span> at the end
282:     const output = [text];
283: 
284:     // If we insert any components we need to wrap the output in a span. React doesn't like just an array of components.
285:     let shouldWrapInSpan = false;
286: 
287:     for (const regexpString in mapping) {
288:         // TODO: Cache regexps
289:         const regexp = new RegExp(regexpString, "g");
290: 
291:         // Loop over what output we have so far and perform replacements
292:         // We look for matches: if we find one, we get three parts: everything before the match, the replaced part,
293:         // and everything after the match. Insert all three into the output. We need to do this because we can insert objects.
294:         // Otherwise there would be no need for the splitting and we could do simple replacement.
295:         let matchFoundSomewhere = false; // If we don't find a match anywhere we want to log it
296:         for (let outputIndex = 0; outputIndex < output.length; outputIndex++) {
297:             const inputText = output[outputIndex];
298:             if (typeof inputText !== 'string') { // We might have inserted objects earlier, don't try to replace them
299:                 continue;
300:             }
301: 
302:             // process every match in the string
303:             // starting with the first
304:             let match = regexp.exec(inputText);
305: 
306:             if (!match) continue;
307:             matchFoundSomewhere = true;
308: 
309:             // The textual part before the first match
310:             const head = inputText.slice(0, match.index);
311: 
312:             const parts = [];
313:             // keep track of prevMatch
314:             let prevMatch;
315:             while (match) {
316:                 // store prevMatch
317:                 prevMatch = match;
318:                 const capturedGroups = match.slice(2);
319: 
320:                 let replaced;
321:                 // If substitution is a function, call it
322:                 if (mapping[regexpString] instanceof Function) {
323:                     replaced = ((mapping as Tags)[regexpString] as Function)(...capturedGroups);
324:                 } else {
325:                     replaced = mapping[regexpString];
326:                 }
327: 
328:                 if (typeof replaced === 'object') {
329:                     shouldWrapInSpan = true;
330:                 }
331: 
332:                 // Here we also need to check that it actually is a string before comparing against one
333:                 // The head and tail are always strings
334:                 if (typeof replaced !== 'string' || replaced !== '') {
335:                     parts.push(replaced);
336:                 }
337: 
338:                 // try the next match
339:                 match = regexp.exec(inputText);
340: 
341:                 // add the text between prevMatch and this one
342:                 // or the end of the string if prevMatch is the last match
343:                 let tail;
344:                 if (match) {
345:                     const startIndex = prevMatch.index + prevMatch[0].length;
346:                     tail = inputText.slice(startIndex, match.index);
347:                 } else {
348:                     tail = inputText.slice(prevMatch.index + prevMatch[0].length);
349:                 }
350:                 if (tail) {
351:                     parts.push(tail);
352:                 }
353:             }
354: 
355:             // Insert in reverse order as splice does insert-before and this way we get the final order correct
356:             // remove the old element at the same time
357:             output.splice(outputIndex, 1, ...parts);
358: 
359:             if (head !== '') { // Don't push empty nodes, they are of no use
360:                 output.splice(outputIndex, 0, head);
361:             }
362:         }
363:         if (!matchFoundSomewhere) { // The current regexp did not match anything in the input
364:             // Missing matches is entirely possible because you might choose to show some variables only in the case
365:             // of e.g. plurals. It's still a bit suspicious, and could be due to an error, so log it.
366:             // However, not showing count is so common that it's not worth logging. And other commonly unused variables
367:             // here, if there are any.
368:             if (regexpString !== '%\\(count\\)s') {
369:                 logger.log(`Could not find ${regexp} in ${text}`);
370:             }
371:         }
372:     }
373: 
374:     if (shouldWrapInSpan) {
375:         return React.createElement('span', null, ...output);
376:     } else {
377:         return output.join('');
378:     }
379: }
