422:         return getLanguageRetry(i18nFolder + availLangs[langToUse].fileName);
423:     }).then(async (langData) => {
424:         counterpart.registerTranslations(langToUse, langData);
425:         await registerCustomTranslations();
426:         counterpart.setLocale(langToUse);
427:         await SettingsStore.setValue("language", null, SettingLevel.DEVICE, langToUse);
