433:         // Set 'en' as fallback language:
434:         if (langToUse !== "en") {
435:             return getLanguageRetry(i18nFolder + availLangs['en'].fileName);
436:         }
437:     }).then(async (langData) => {
438:         if (langData) counterpart.registerTranslations('en', langData);
