473: /**
474:  * Turns a language string, normalises it,
475:  * (see normalizeLanguageKey) into an array of language strings
476:  * with fallback to generic languages
477:  * (eg. 'pt-BR' => ['pt-br', 'pt'])
478:  *
479:  * @param {string} language The input language string
480:  * @return {string[]} List of normalised languages
481:  */
482: export function getNormalizedLanguageKeys(language: string) {
483:     const languageKeys: string[] = [];
484:     const normalizedLanguage = normalizeLanguageKey(language);
485:     const languageParts = normalizedLanguage.split('-');
486:     if (languageParts.length === 2 && languageParts[0] === languageParts[1]) {
487:         languageKeys.push(languageParts[0]);
488:     } else {
489:         languageKeys.push(normalizedLanguage);
490:         if (languageParts.length === 2) {
491:             languageKeys.push(languageParts[0]);
492:         }
493:     }
494:     return languageKeys;
495: }
