512: /**
513:  * Given a list of language codes, pick the most appropriate one
514:  * given the current language (ie. getCurrentLanguage())
515:  * English is assumed to be a reasonable default.
516:  *
517:  * @param {string[]} langs List of language codes to pick from
518:  * @returns {string} The most appropriate language code from langs
519:  */
520: export function pickBestLanguage(langs: string[]): string {
521:     const currentLang = getCurrentLanguage();
522:     const normalisedLangs = langs.map(normalizeLanguageKey);
523: 
524:     {
525:         // Best is an exact match
526:         const currentLangIndex = normalisedLangs.indexOf(currentLang);
527:         if (currentLangIndex > -1) return langs[currentLangIndex];
528:     }
529: 
530:     {
531:         // Failing that, a different dialect of the same language
532:         const closeLangIndex = normalisedLangs.findIndex((l) => l.slice(0, 2) === currentLang.slice(0, 2));
533:         if (closeLangIndex > -1) return langs[closeLangIndex];
534:     }
535: 
536:     {
537:         // Neither of those? Try an english variant.
538:         const enIndex = normalisedLangs.findIndex((l) => l.startsWith('en'));
539:         if (enIndex > -1) return langs[enIndex];
540:     }
541: 
542:     // if nothing else, use the first
543:     return langs[0];
544: }
