587: export interface ICustomTranslations {
588:     // Format is a map of english string to language to override
589:     [str: string]: {
590:         [lang: string]: string;
591:     };
592: }
593: 
594: let cachedCustomTranslations: Optional<ICustomTranslations> = null;
595: let cachedCustomTranslationsExpire = 0; // zero to trigger expiration right away
596: 
597: // This awkward class exists so the test runner can get at the function. It is
598: // not intended for practical or realistic usage.
599: export class CustomTranslationOptions {
600:     public static lookupFn: (url: string) => ICustomTranslations;
601: 
602:     private constructor() {
603:         // static access for tests only
604:     }
605: }
606: 
607: function doRegisterTranslations(customTranslations: ICustomTranslations) {
608:     // We convert the operator-friendly version into something counterpart can
609:     // consume.
610:     const langs: {
611:         // same structure, just flipped key order
612:         [lang: string]: {
613:             [str: string]: string;
614:         };
615:     } = {};
616:     for (const [str, translations] of Object.entries(customTranslations)) {
617:         for (const [lang, newStr] of Object.entries(translations)) {
618:             if (!langs[lang]) langs[lang] = {};
619:             langs[lang][str] = newStr;
620:         }
621:     }
622: 
623:     // Finally, tell counterpart about our translations
624:     for (const [lang, translations] of Object.entries(langs)) {
625:         counterpart.registerTranslations(lang, translations);
626:     }
627: }
628: 
629: /**
630:  * Any custom modules with translations to load are parsed first, followed by an
631:  * optionally defined translations file in the config. If no customization is made,
632:  * or the file can't be parsed, no action will be taken.
633:  *
634:  * This function should be called *after* registering other translations data to
635:  * ensure it overrides strings properly.
636:  */
637: export async function registerCustomTranslations() {
638:     const moduleTranslations = ModuleRunner.instance.allTranslations;
639:     doRegisterTranslations(moduleTranslations);
640: 
641:     const lookupUrl = SdkConfig.get().custom_translations_url;
642:     if (!lookupUrl) return; // easy - nothing to do
643: 
644:     try {
645:         let json: ICustomTranslations;
646:         if (Date.now() >= cachedCustomTranslationsExpire) {
647:             json = CustomTranslationOptions.lookupFn
648:                 ? CustomTranslationOptions.lookupFn(lookupUrl)
649:                 : (await (await fetch(lookupUrl)).json() as ICustomTranslations);
650:             cachedCustomTranslations = json;
651: 
652:             // Set expiration to the future, but not too far. Just trying to avoid
653:             // repeated, successive, calls to the server rather than anything long-term.
654:             cachedCustomTranslationsExpire = Date.now() + (5 * 60 * 1000);
655:         } else {
656:             json = cachedCustomTranslations;
657:         }
658: 
659:         // If the (potentially cached) json is invalid, don't use it.
660:         if (!json) return;
661: 
662:         // Finally, register it.
663:         doRegisterTranslations(json);
664:     } catch (e) {
665:         // We consume all exceptions because it's considered non-fatal for custom
666:         // translations to break. Most failures will be during initial development
667:         // of the json file and not (hopefully) at runtime.
668:         logger.warn("Ignoring error while registering custom translations: ", e);
669: 
670:         // Like above: trigger a cache of the json to avoid successive calls.
671:         cachedCustomTranslationsExpire = Date.now() + (5 * 60 * 1000);
672:     }
673: }
