165:     public userRegisteredWithinLastHours(hours: number): boolean {
166:         if (hours <= 0) {
167:             return false;
168:         }
169: 
170:         try {
171:             const registrationTime = parseInt(window.localStorage.getItem("mx_registration_time"), 10);
172:             const diff = Date.now() - registrationTime;
173:             return (diff / 36e5) <= hours;
174:         } catch (e) {
175:             return false;
176:         }
177:     }
