179:     public userRegisteredAfter(timestamp: Date): boolean {
180:         try {
181:             const registrationTime = parseInt(window.localStorage.getItem("mx_registration_time"), 10);
182:             return timestamp.getTime() <= registrationTime;
183:         } catch (e) {
184:             return false;
185:         }
186:     }
