193:     public async assign(): Promise<any> {
194:         for (const dbType of ['indexeddb', 'memory']) {
195:             try {
196:                 const promise = this.matrixClient.store.startup();
197:                 logger.log("MatrixClientPeg: waiting for MatrixClient store to initialise");
198:                 await promise;
199:                 break;
200:             } catch (err) {
201:                 if (dbType === 'indexeddb') {
202:                     logger.error('Error starting matrixclient store - falling back to memory store', err);
203:                     this.matrixClient.store = new MemoryStore({
204:                         localStorage: localStorage,
205:                     });
206:                 } else {
207:                     logger.error('Failed to start memory store!', err);
208:                     throw err;
209:                 }
210:             }
211:         }
212: 
213:         // try to initialise e2e on the new client
214:         try {
215:             // check that we have a version of the js-sdk which includes initCrypto
216:             if (!SettingsStore.getValue("lowBandwidth") && this.matrixClient.initCrypto) {
217:                 await this.matrixClient.initCrypto();
218:                 this.matrixClient.setCryptoTrustCrossSignedDevices(
219:                     !SettingsStore.getValue('e2ee.manuallyVerifyAllSessions'),
220:                 );
221:                 await tryToUnlockSecretStorageWithDehydrationKey(this.matrixClient);
222:                 StorageManager.setCryptoInitialised(true);
223:             }
224:         } catch (e) {
225:             if (e && e.name === 'InvalidCryptoStoreError') {
226:                 // The js-sdk found a crypto DB too new for it to use
227:                 Modal.createDialog(CryptoStoreTooNewDialog);
228:             }
229:             // this can happen for a number of reasons, the most likely being
230:             // that the olm library was missing. It's not fatal.
231:             logger.warn("Unable to initialise e2e", e);
232:         }
233: 
234:         const opts = utils.deepCopy(this.opts);
235:         // the react sdk doesn't work without this, so don't allow
236:         opts.pendingEventOrdering = PendingEventOrdering.Detached;
237:         opts.lazyLoadMembers = true;
238:         opts.clientWellKnownPollPeriod = 2 * 60 * 60; // 2 hours
239:         opts.experimentalThreadSupport = SettingsStore.getValue("feature_thread");
240: 
241:         if (SettingsStore.getValue("feature_sliding_sync")) {
242:             const proxyUrl = SettingsStore.getValue("feature_sliding_sync_proxy_url");
243:             if (proxyUrl) {
244:                 logger.log("Activating sliding sync using proxy at ", proxyUrl);
245:             } else {
246:                 logger.log("Activating sliding sync");
247:             }
248:             opts.slidingSync = SlidingSyncManager.instance.configure(
249:                 this.matrixClient,
250:                 proxyUrl || this.matrixClient.baseUrl,
251:             );
252:             SlidingSyncManager.instance.startSpidering(100, 50); // 100 rooms at a time, 50ms apart
253:         }
254: 
255:         // Connect the matrix client to the dispatcher and setting handlers
256:         MatrixActionCreators.start(this.matrixClient);
257:         MatrixClientBackedSettingsHandler.matrixClient = this.matrixClient;
258: 
259:         return opts;
260:     }
