262:     public async start(): Promise<any> {
263:         const opts = await this.assign();
264: 
265:         logger.log(`MatrixClientPeg: really starting MatrixClient`);
266:         await this.get().startClient(opts);
267:         logger.log(`MatrixClientPeg: MatrixClient started`);
268:     }
