270:     public getCredentials(): IMatrixClientCreds {
271:         let copiedCredentials = this.currentClientCreds;
272:         if (this.currentClientCreds?.userId !== this.matrixClient?.credentials?.userId) {
273:             // cached credentials belong to a different user - don't use them
274:             copiedCredentials = null;
275:         }
276:         return {
277:             // Copy the cached credentials before overriding what we can.
278:             ...(copiedCredentials ?? {}),
279: 
280:             homeserverUrl: this.matrixClient.baseUrl,
281:             identityServerUrl: this.matrixClient.idBaseUrl,
282:             userId: this.matrixClient.credentials.userId,
283:             deviceId: this.matrixClient.getDeviceId(),
284:             accessToken: this.matrixClient.getAccessToken(),
285:             guest: this.matrixClient.isGuest(),
286:         };
287:     }
