289:     public getHomeserverName(): string {
290:         const matches = /^@[^:]+:(.+)$/.exec(this.matrixClient.credentials.userId);
291:         if (matches === null || matches.length < 1) {
292:             throw new Error("Failed to derive homeserver name from user ID!");
293:         }
294:         return matches[1];
295:     }
