297:     private namesToRoomName(names: string[], count: number): string | undefined {
298:         const countWithoutMe = count - 1;
299:         if (!names.length) {
300:             return _t("Empty room");
301:         }
302:         if (names.length === 1 && countWithoutMe <= 1) {
303:             return names[0];
304:         }
305:     }
306: 
307:     private memberNamesToRoomName(names: string[], count: number): string {
308:         const name = this.namesToRoomName(names, count);
309:         if (name) return name;
310: 
311:         if (names.length === 2 && count === 2) {
312:             return _t("%(user1)s and %(user2)s", {
313:                 user1: names[0],
314:                 user2: names[1],
315:             });
316:         }
317:         return _t("%(user)s and %(count)s others", {
318:             user: names[0],
319:             count: count - 1,
320:         });
321:     }
322: 
323:     private inviteeNamesToRoomName(names: string[], count: number): string {
324:         const name = this.namesToRoomName(names, count);
325:         if (name) return name;
326: 
327:         if (names.length === 2 && count === 2) {
328:             return _t("Inviting %(user1)s and %(user2)s", {
329:                 user1: names[0],
330:                 user2: names[1],
331:             });
332:         }
333:         return _t("Inviting %(user)s and %(count)s others", {
334:             user: names[0],
335:             count: count - 1,
336:         });
337:     }
338: 
339:     private createClient(creds: IMatrixClientCreds): void {
340:         const opts: ICreateClientOpts = {
341:             baseUrl: creds.homeserverUrl,
342:             idBaseUrl: creds.identityServerUrl,
343:             accessToken: creds.accessToken,
344:             userId: creds.userId,
345:             deviceId: creds.deviceId,
346:             pickleKey: creds.pickleKey,
347:             timelineSupport: true,
348:             forceTURN: !SettingsStore.getValue('webRtcAllowPeerToPeer'),
349:             fallbackICEServerAllowed: !!SettingsStore.getValue('fallbackICEServerAllowed'),
350:             // Gather up to 20 ICE candidates when a call arrives: this should be more than we'd
351:             // ever normally need, so effectively this should make all the gathering happen when
352:             // the call arrives.
353:             iceCandidatePoolSize: 20,
354:             verificationMethods: [
355:                 verificationMethods.SAS,
356:                 SHOW_QR_CODE_METHOD,
357:                 verificationMethods.RECIPROCATE_QR_CODE,
358:             ],
359:             identityServer: new IdentityAuthClient(),
360:             // These are always installed regardless of the labs flag so that cross-signing features
361:             // can toggle on without reloading and also be accessed immediately after login.
362:             cryptoCallbacks: { ...crossSigningCallbacks },
363:             roomNameGenerator: (_: string, state: RoomNameState) => {
364:                 switch (state.type) {
365:                     case RoomNameType.Generated:
366:                         switch (state.subtype) {
367:                             case "Inviting":
368:                                 return this.inviteeNamesToRoomName(state.names, state.count);
369:                             default:
370:                                 return this.memberNamesToRoomName(state.names, state.count);
371:                         }
372:                     case RoomNameType.EmptyRoom:
373:                         if (state.oldName) {
374:                             return _t("Empty room (was %(oldName)s)", {
375:                                 oldName: state.oldName,
376:                             });
377:                         } else {
378:                             return _t("Empty room");
379:                         }
380:                     default:
381:                         return null;
382:                 }
383:             },
384:         };
385: 
386:         if (SecurityCustomisations.getDehydrationKey) {
387:             opts.cryptoCallbacks!.getDehydrationKey = SecurityCustomisations.getDehydrationKey;
388:         }
389: 
390:         this.matrixClient = createMatrixClient(opts);
391: 
392:         // we're going to add eventlisteners for each matrix event tile, so the
393:         // potential number of event listeners is quite high.
394:         this.matrixClient.setMaxListeners(500);
395: 
396:         this.matrixClient.setGuest(Boolean(creds.guest));
397: 
398:         const notifTimelineSet = new EventTimelineSet(undefined, {
399:             timelineSupport: true,
400:             pendingEvents: false,
401:         });
402:         // XXX: what is our initial pagination token?! it somehow needs to be synchronised with /sync.
403:         notifTimelineSet.getLiveTimeline().setPaginationToken("", EventTimeline.BACKWARDS);
404:         this.matrixClient.setNotifTimelineSet(notifTimelineSet);
405:     }
406: }
