42: const defaultWatchManager = new WatchManager();
43: 
44: // Convert the settings to easier to manage objects for the handlers
45: const defaultSettings = {};
46: const invertedDefaultSettings = {};
47: const featureNames = [];
48: for (const key of Object.keys(SETTINGS)) {
49:     defaultSettings[key] = SETTINGS[key].default;
50:     if (SETTINGS[key].isFeature) featureNames.push(key);
51:     if (SETTINGS[key].invertedSettingName) {
52:         // Invert now so that the rest of the system will invert it back
53:         // to what was intended.
54:         invertedDefaultSettings[SETTINGS[key].invertedSettingName] = !SETTINGS[key].default;
55:     }
56: }
57: 
58: // Only wrap the handlers with async setters in a local echo wrapper
59: const LEVEL_HANDLERS = {
60:     [SettingLevel.DEVICE]: new DeviceSettingsHandler(featureNames, defaultWatchManager),
61:     [SettingLevel.ROOM_DEVICE]: new RoomDeviceSettingsHandler(defaultWatchManager),
62:     [SettingLevel.ROOM_ACCOUNT]: new LocalEchoWrapper(
63:         new RoomAccountSettingsHandler(defaultWatchManager),
64:         SettingLevel.ROOM_ACCOUNT,
65:     ),
66:     [SettingLevel.ACCOUNT]: new LocalEchoWrapper(new AccountSettingsHandler(defaultWatchManager), SettingLevel.ACCOUNT),
67:     [SettingLevel.ROOM]: new LocalEchoWrapper(new RoomSettingsHandler(defaultWatchManager), SettingLevel.ROOM),
68:     [SettingLevel.PLATFORM]: new LocalEchoWrapper(new PlatformSettingsHandler(), SettingLevel.PLATFORM),
69:     [SettingLevel.CONFIG]: new ConfigSettingsHandler(featureNames),
70:     [SettingLevel.DEFAULT]: new DefaultSettingsHandler(defaultSettings, invertedDefaultSettings),
71: };
72: 
73: export const LEVEL_ORDER = [
74:     SettingLevel.DEVICE,
75:     SettingLevel.ROOM_DEVICE,
76:     SettingLevel.ROOM_ACCOUNT,
77:     SettingLevel.ACCOUNT,
78:     SettingLevel.ROOM,
79:     SettingLevel.CONFIG,
80:     SettingLevel.DEFAULT,
81: ];
82: 
83: function getLevelOrder(setting: ISetting): SettingLevel[] {
84:     // Settings which support only a single setting level are inherently ordered
85:     if (setting.supportedLevelsAreOrdered || setting.supportedLevels.length === 1) {
86:         // return a copy to prevent callers from modifying the array
87:         return [...setting.supportedLevels];
88:     }
89:     return LEVEL_ORDER;
90: }
