92: export type CallbackFn = (
93:     settingName: string,
94:     roomId: string,
95:     atLevel: SettingLevel,
96:     newValAtLevel: any,
97:     newVal: any,
98: ) => void;
99: 
100: interface IHandlerMap {
101:     // @ts-ignore - TS wants this to be a string key but we know better
102:     [level: SettingLevel]: SettingsHandler;
103: }
104: 
105: /**
106:  * Controls and manages application settings by providing varying levels at which the
107:  * setting value may be specified. The levels are then used to determine what the setting
108:  * value should be given a set of circumstances. The levels, in priority order, are:
109:  * - SettingLevel.DEVICE         - Values are determined by the current device
110:  * - SettingLevel.ROOM_DEVICE    - Values are determined by the current device for a particular room
111:  * - SettingLevel.ROOM_ACCOUNT   - Values are determined by the current account for a particular room
112:  * - SettingLevel.ACCOUNT        - Values are determined by the current account
113:  * - SettingLevel.ROOM           - Values are determined by a particular room (by the room admins)
114:  * - SettingLevel.CONFIG         - Values are determined by the config.json
115:  * - SettingLevel.DEFAULT        - Values are determined by the hardcoded defaults
116:  *
117:  * Each level has a different method to storing the setting value. For implementation
118:  * specific details, please see the handlers. The "config" and "default" levels are
119:  * both always supported on all platforms. All other settings should be guarded by
120:  * isLevelSupported() prior to attempting to set the value.
121:  *
122:  * Settings can also represent features. Features are significant portions of the
123:  * application that warrant a dedicated setting to toggle them on or off. Features are
124:  * special-cased to ensure that their values respect the configuration (for example, a
125:  * feature may be reported as disabled even though a user has specifically requested it
126:  * be enabled).
127:  */
128: export default class SettingsStore {
129:     // We support watching settings for changes, and do this by tracking which callbacks have
130:     // been given to us. We end up returning the callbackRef to the caller so they can unsubscribe
131:     // at a later point.
132:     //
133:     // We also maintain a list of monitors which are special watchers: they cause dispatches
134:     // when the setting changes. We track which rooms we're monitoring though to ensure we
135:     // don't duplicate updates on the bus.
136:     private static watchers = new Map<string, WatchCallbackFn>();
137:     private static monitors = new Map<string, Map<string, string>>(); // { settingName => { roomId => callbackRef } }
138: 
139:     // Counter used for generation of watcher IDs
140:     private static watcherCount = 1;
141: 
142:     /**
143:      * Gets all the feature-style setting names.
144:      * @returns {string[]} The names of the feature settings.
145:      */
146:     public static getFeatureSettingNames(): string[] {
147:         return Object.keys(SETTINGS).filter(n => SettingsStore.isFeature(n));
148:     }
149: 
150:     /**
151:      * Watches for changes in a particular setting. This is done without any local echo
152:      * wrapping and fires whenever a change is detected in a setting's value, at any level.
153:      * Watching is intended to be used in scenarios where the app needs to react to changes
154:      * made by other devices. It is otherwise expected that callers will be able to use the
155:      * Controller system or track their own changes to settings. Callers should retain the
156:      * returned reference to later unsubscribe from updates.
157:      * @param {string} settingName The setting name to watch
158:      * @param {String} roomId The room ID to watch for changes in. May be null for 'all'.
159:      * @param {function} callbackFn A function to be called when a setting change is
160:      * detected. Five arguments can be expected: the setting name, the room ID (may be null),
161:      * the level the change happened at, the new value at the given level, and finally the new
162:      * value for the setting regardless of level. The callback is responsible for determining
163:      * if the change in value is worthwhile enough to react upon.
164:      * @returns {string} A reference to the watcher that was employed.
165:      */
166:     public static watchSetting(settingName: string, roomId: string | null, callbackFn: CallbackFn): string {
167:         const setting = SETTINGS[settingName];
168:         const originalSettingName = settingName;
169:         if (!setting) throw new Error(`${settingName} is not a setting`);
170: 
171:         if (setting.invertedSettingName) {
172:             settingName = setting.invertedSettingName;
173:         }
174: 
175:         const watcherId = `${new Date().getTime()}_${SettingsStore.watcherCount++}_${settingName}_${roomId}`;
176: 
177:         const localizedCallback = (changedInRoomId: string | null, atLevel: SettingLevel, newValAtLevel: any) => {
178:             if (!SettingsStore.doesSettingSupportLevel(originalSettingName, atLevel)) {
179:                 logger.warn(
180:                     `Setting handler notified for an update of an invalid setting level: ` +
181:                     `${originalSettingName}@${atLevel} - this likely means a weird setting value ` +
182:                     `made it into the level's storage. The notification will be ignored.`,
183:                 );
184:                 return;
185:             }
186:             const newValue = SettingsStore.getValue(originalSettingName);
187:             const newValueAtLevel = SettingsStore.getValueAt(atLevel, originalSettingName) ?? newValAtLevel;
188:             callbackFn(originalSettingName, changedInRoomId, atLevel, newValueAtLevel, newValue);
189:         };
190: 
191:         SettingsStore.watchers.set(watcherId, localizedCallback);
192:         defaultWatchManager.watchSetting(settingName, roomId, localizedCallback);
193: 
194:         return watcherId;
195:     }
196: 
197:     /**
198:      * Stops the SettingsStore from watching a setting. This is a no-op if the watcher
199:      * provided is not found.
200:      * @param {string} watcherReference The watcher reference (received from #watchSetting)
201:      * to cancel.
202:      */
203:     public static unwatchSetting(watcherReference: string) {
204:         if (!SettingsStore.watchers.has(watcherReference)) {
205:             logger.warn(`Ending non-existent watcher ID ${watcherReference}`);
206:             return;
207:         }
208: 
209:         defaultWatchManager.unwatchSetting(SettingsStore.watchers.get(watcherReference));
210:         SettingsStore.watchers.delete(watcherReference);
211:     }
212: 
213:     /**
214:      * Sets up a monitor for a setting. This behaves similar to #watchSetting except instead
215:      * of making a call to a callback, it forwards all changes to the dispatcher. Callers can
216:      * expect to listen for the 'setting_updated' action with an object containing settingName,
217:      * roomId, level, newValueAtLevel, and newValue.
218:      * @param {string} settingName The setting name to monitor.
219:      * @param {String} roomId The room ID to monitor for changes in. Use null for all rooms.
220:      */
221:     public static monitorSetting(settingName: string, roomId: string | null) {
222:         roomId = roomId || null; // the thing wants null specifically to work, so appease it.
223: 
224:         if (!this.monitors.has(settingName)) this.monitors.set(settingName, new Map());
225: 
226:         const registerWatcher = () => {
227:             this.monitors.get(settingName).set(roomId, SettingsStore.watchSetting(
228:                 settingName, roomId, (settingName, inRoomId, level, newValueAtLevel, newValue) => {
229:                     dis.dispatch<SettingUpdatedPayload>({
230:                         action: Action.SettingUpdated,
231:                         settingName,
232:                         roomId: inRoomId,
233:                         level,
234:                         newValueAtLevel,
235:                         newValue,
236:                     });
237:                 },
238:             ));
239:         };
240: 
241:         const rooms = Array.from(this.monitors.get(settingName).keys());
242:         const hasRoom = rooms.find((r) => r === roomId || r === null);
243:         if (!hasRoom) {
244:             registerWatcher();
245:         } else {
246:             if (roomId === null) {
247:                 // Unregister all existing watchers and register the new one
248:                 rooms.forEach(roomId => {
249:                     SettingsStore.unwatchSetting(this.monitors.get(settingName).get(roomId));
250:                 });
251:                 this.monitors.get(settingName).clear();
252:                 registerWatcher();
253:             } // else a watcher is already registered for the room, so don't bother registering it again
254:         }
255:     }
256: 
257:     /**
258:      * Gets the translated display name for a given setting
259:      * @param {string} settingName The setting to look up.
260:      * @param {SettingLevel} atLevel
261:      * The level to get the display name for; Defaults to 'default'.
262:      * @return {String} The display name for the setting, or null if not found.
263:      */
264:     public static getDisplayName(settingName: string, atLevel = SettingLevel.DEFAULT) {
265:         if (!SETTINGS[settingName] || !SETTINGS[settingName].displayName) return null;
266: 
267:         let displayName = SETTINGS[settingName].displayName;
268:         if (displayName instanceof Object) {
269:             if (displayName[atLevel]) displayName = displayName[atLevel];
270:             else displayName = displayName["default"];
271:         }
272: 
273:         return _t(displayName as string);
274:     }
275: 
276:     /**
277:      * Gets the translated description for a given setting
278:      * @param {string} settingName The setting to look up.
279:      * @return {String} The description for the setting, or null if not found.
280:      */
281:     public static getDescription(settingName: string): string | ReactNode {
282:         const description = SETTINGS[settingName]?.description;
283:         if (!description) return null;
284:         if (typeof description !== 'string') return description();
285:         return _t(description);
286:     }
287: 
288:     /**
289:      * Determines if a setting is also a feature.
290:      * @param {string} settingName The setting to look up.
291:      * @return {boolean} True if the setting is a feature.
292:      */
293:     public static isFeature(settingName: string) {
294:         if (!SETTINGS[settingName]) return false;
295:         return SETTINGS[settingName].isFeature;
296:     }
297: 
298:     public static getBetaInfo(settingName: string): ISetting["betaInfo"] {
299:         // consider a beta disabled if the config is explicitly set to false, in which case treat as normal Labs flag
300:         if (SettingsStore.isFeature(settingName)
301:             && SettingsStore.getValueAt(SettingLevel.CONFIG, settingName, null, true, true) !== false
302:         ) {
303:             return SETTINGS[settingName]?.betaInfo;
304:         }
305:     }
306: 
307:     public static getLabGroup(settingName: string): LabGroup {
308:         if (SettingsStore.isFeature(settingName)) {
309:             return (<IFeature>SETTINGS[settingName]).labsGroup;
310:         }
311:     }
312: 
313:     /**
314:      * Determines if a setting is enabled.
315:      * If a setting is disabled then it should be hidden from the user.
316:      * @param {string} settingName The setting to look up.
317:      * @return {boolean} True if the setting is enabled.
318:      */
319:     public static isEnabled(settingName: string): boolean {
320:         if (!SETTINGS[settingName]) return false;
321:         return SETTINGS[settingName].controller ? !SETTINGS[settingName].controller.settingDisabled : true;
322:     }
323: 
324:     /**
325:      * Gets the value of a setting. The room ID is optional if the setting is not to
326:      * be applied to any particular room, otherwise it should be supplied.
327:      * @param {string} settingName The name of the setting to read the value of.
328:      * @param {String} roomId The room ID to read the setting value in, may be null.
329:      * @param {boolean} excludeDefault True to disable using the default value.
330:      * @return {*} The value, or null if not found
331:      */
332:     public static getValue<T = any>(settingName: string, roomId: string = null, excludeDefault = false): T {
333:         // Verify that the setting is actually a setting
334:         if (!SETTINGS[settingName]) {
335:             throw new Error("Setting '" + settingName + "' does not appear to be a setting.");
336:         }
337: 
338:         const setting = SETTINGS[settingName];
339:         const levelOrder = getLevelOrder(setting);
340: 
341:         return SettingsStore.getValueAt(levelOrder[0], settingName, roomId, false, excludeDefault);
342:     }
343: 
344:     /**
345:      * Gets a setting's value at a particular level, ignoring all levels that are more specific.
346:      * @param {SettingLevel|"config"|"default"} level The
347:      * level to look at.
348:      * @param {string} settingName The name of the setting to read.
349:      * @param {String} roomId The room ID to read the setting value in, may be null.
350:      * @param {boolean} explicit If true, this method will not consider other levels, just the one
351:      * provided. Defaults to false.
352:      * @param {boolean} excludeDefault True to disable using the default value.
353:      * @return {*} The value, or null if not found.
354:      */
355:     public static getValueAt(
356:         level: SettingLevel,
357:         settingName: string,
358:         roomId: string = null,
359:         explicit = false,
360:         excludeDefault = false,
361:     ): any {
362:         // Verify that the setting is actually a setting
363:         const setting = SETTINGS[settingName];
364:         if (!setting) {
365:             throw new Error("Setting '" + settingName + "' does not appear to be a setting.");
366:         }
367: 
368:         const levelOrder = getLevelOrder(setting);
369:         if (!levelOrder.includes(SettingLevel.DEFAULT)) levelOrder.push(SettingLevel.DEFAULT); // always include default
370: 
371:         const minIndex = levelOrder.indexOf(level);
372:         if (minIndex === -1) throw new Error(`Level "${level}" for setting "${settingName}" is not prioritized`);
373: 
374:         const handlers = SettingsStore.getHandlers(settingName);
375: 
376:         // Check if we need to invert the setting at all. Do this after we get the setting
377:         // handlers though, otherwise we'll fail to read the value.
378:         if (setting.invertedSettingName) {
379:             //console.warn(`Inverting ${settingName} to be ${setting.invertedSettingName} - legacy setting`);
380:             settingName = setting.invertedSettingName;
381:         }
382: 
383:         if (explicit) {
384:             const handler = handlers[level];
385:             if (!handler) {
386:                 return SettingsStore.getFinalValue(setting, level, roomId, null, null);
387:             }
388:             const value = handler.getValue(settingName, roomId);
389:             return SettingsStore.getFinalValue(setting, level, roomId, value, level);
390:         }
391: 
392:         for (let i = minIndex; i < levelOrder.length; i++) {
393:             const handler = handlers[levelOrder[i]];
394:             if (!handler) continue;
395:             if (excludeDefault && levelOrder[i] === "default") continue;
396: 
397:             const value = handler.getValue(settingName, roomId);
398:             if (value === null || value === undefined) continue;
399:             return SettingsStore.getFinalValue(setting, level, roomId, value, levelOrder[i]);
400:         }
401: 
402:         return SettingsStore.getFinalValue(setting, level, roomId, null, null);
403:     }
404: 
405:     /**
406:      * Gets the default value of a setting.
407:      * @param {string} settingName The name of the setting to read the value of.
408:      * @param {String} roomId The room ID to read the setting value in, may be null.
409:      * @return {*} The default value
410:      */
411:     public static getDefaultValue(settingName: string): any {
412:         // Verify that the setting is actually a setting
413:         if (!SETTINGS[settingName]) {
414:             throw new Error("Setting '" + settingName + "' does not appear to be a setting.");
415:         }
416: 
417:         return SETTINGS[settingName].default;
418:     }
419: 
420:     private static getFinalValue(
421:         setting: ISetting,
422:         level: SettingLevel,
423:         roomId: string,
424:         calculatedValue: any,
425:         calculatedAtLevel: SettingLevel,
426:     ): any {
427:         let resultingValue = calculatedValue;
428: 
429:         if (setting.controller) {
430:             const actualValue = setting.controller.getValueOverride(level, roomId, calculatedValue, calculatedAtLevel);
431:             if (actualValue !== undefined && actualValue !== null) resultingValue = actualValue;
432:         }
433: 
434:         if (setting.invertedSettingName) resultingValue = !resultingValue;
435:         return resultingValue;
436:     }
437: 
438:     /* eslint-disable valid-jsdoc */ //https://github.com/eslint/eslint/issues/7307
439:     /**
440:      * Sets the value for a setting. The room ID is optional if the setting is not being
441:      * set for a particular room, otherwise it should be supplied. The value may be null
442:      * to indicate that the level should no longer have an override.
443:      * @param {string} settingName The name of the setting to change.
444:      * @param {String} roomId The room ID to change the value in, may be null.
445:      * @param {SettingLevel} level The level
446:      * to change the value at.
447:      * @param {*} value The new value of the setting, may be null.
448:      * @return {Promise} Resolves when the setting has been changed.
449:      */
450: 
451:     /* eslint-enable valid-jsdoc */
452:     public static async setValue(
453:         settingName: string,
454:         roomId: string | null,
455:         level: SettingLevel,
456:         value: any,
457:     ): Promise<void> {
458:         // Verify that the setting is actually a setting
459:         const setting = SETTINGS[settingName];
460:         if (!setting) {
461:             throw new Error("Setting '" + settingName + "' does not appear to be a setting.");
462:         }
463: 
464:         const handler = SettingsStore.getHandler(settingName, level);
465:         if (!handler) {
466:             throw new Error("Setting " + settingName + " does not have a handler for " + level);
467:         }
468: 
469:         if (setting.invertedSettingName) {
470:             // Note: We can't do this when the `level` is "default", however we also
471:             // know that the user can't possible change the default value through this
472:             // function so we don't bother checking it.
473:             //console.warn(`Inverting ${settingName} to be ${setting.invertedSettingName} - legacy setting`);
474:             settingName = setting.invertedSettingName;
475:             value = !value;
476:         }
477: 
478:         if (!handler.canSetValue(settingName, roomId)) {
479:             throw new Error("User cannot set " + settingName + " at " + level + " in " + roomId);
480:         }
481: 
482:         if (setting.controller && !(await setting.controller.beforeChange(level, roomId, value))) {
483:             return; // controller says no
484:         }
485: 
486:         await handler.setValue(settingName, roomId, value);
487: 
488:         setting.controller?.onChange(level, roomId, value);
489:     }
490: 
491:     /**
492:      * Determines if the current user is permitted to set the given setting at the given
493:      * level for a particular room. The room ID is optional if the setting is not being
494:      * set for a particular room, otherwise it should be supplied.
495:      * @param {string} settingName The name of the setting to check.
496:      * @param {String} roomId The room ID to check in, may be null.
497:      * @param {SettingLevel} level The level to
498:      * check at.
499:      * @return {boolean} True if the user may set the setting, false otherwise.
500:      */
501:     public static canSetValue(settingName: string, roomId: string, level: SettingLevel): boolean {
502:         // Verify that the setting is actually a setting
503:         if (!SETTINGS[settingName]) {
504:             throw new Error("Setting '" + settingName + "' does not appear to be a setting.");
505:         }
506: 
507:         if (!SettingsStore.isEnabled(settingName)) {
508:             return false;
509:         }
510: 
511:         // When non-beta features are specified in the config.json, we force them as enabled or disabled.
512:         if (SettingsStore.isFeature(settingName) && !SETTINGS[settingName]?.betaInfo) {
513:             const configVal = SettingsStore.getValueAt(SettingLevel.CONFIG, settingName, roomId, true, true);
514:             if (configVal === true || configVal === false) return false;
515:         }
516: 
517:         const handler = SettingsStore.getHandler(settingName, level);
518:         if (!handler) return false;
519:         return handler.canSetValue(settingName, roomId);
520:     }
521: 
522:     /**
523:      * Determines if the given level is supported on this device.
524:      * @param {SettingLevel} level The level
525:      * to check the feasibility of.
526:      * @return {boolean} True if the level is supported, false otherwise.
527:      */
528:     public static isLevelSupported(level: SettingLevel): boolean {
529:         if (!LEVEL_HANDLERS[level]) return false;
530:         return LEVEL_HANDLERS[level].isSupported();
531:     }
532: 
533:     /**
534:      * Determines if a setting supports a particular level.
535:      * @param settingName The setting name.
536:      * @param level The level.
537:      * @returns True if supported, false otherwise. Note that this will not check to see if
538:      * the level itself can be supported by the runtime (ie: you will need to call #isLevelSupported()
539:      * on your own).
540:      */
541:     public static doesSettingSupportLevel(settingName: string, level: SettingLevel): boolean {
542:         const setting = SETTINGS[settingName];
543:         if (!setting) {
544:             throw new Error("Setting '" + settingName + "' does not appear to be a setting.");
545:         }
546: 
547:         return level === SettingLevel.DEFAULT || (setting.supportedLevels.includes(level));
548:     }
549: 
550:     /**
551:      * Determines the first supported level out of all the levels that can be used for a
552:      * specific setting.
553:      * @param {string} settingName The setting name.
554:      * @return {SettingLevel}
555:      */
556:     public static firstSupportedLevel(settingName: string): SettingLevel {
557:         // Verify that the setting is actually a setting
558:         const setting = SETTINGS[settingName];
559:         if (!setting) {
560:             throw new Error("Setting '" + settingName + "' does not appear to be a setting.");
561:         }
562: 
563:         const levelOrder = getLevelOrder(setting);
564:         if (!levelOrder.includes(SettingLevel.DEFAULT)) levelOrder.push(SettingLevel.DEFAULT); // always include default
565: 
566:         const handlers = SettingsStore.getHandlers(settingName);
567: 
568:         for (const level of levelOrder) {
569:             const handler = handlers[level];
570:             if (!handler) continue;
571:             return level;
572:         }
573:         return null;
574:     }
575: 
576:     /**
577:      * Runs or queues any setting migrations needed.
578:      */
579:     public static runMigrations(): void {
580:         // Dev notes: to add your migration, just add a new `migrateMyFeature` function, call it, and
581:         // add a comment to note when it can be removed.
582: 
583:         SettingsStore.migrateHiddenReadReceipts(); // Can be removed after October 2022.
584:     }
585: 
586:     private static migrateHiddenReadReceipts(): void {
587:         if (MatrixClientPeg.get().isGuest()) return; // not worth it
588: 
589:         // We wait for the first sync to ensure that the user's existing account data has loaded, as otherwise
590:         // getValue() for an account-level setting like sendReadReceipts will return `null`.
591:         const disRef = dispatcher.register((payload: ActionPayload) => {
592:             if (payload.action === "MatrixActions.sync") {
593:                 dispatcher.unregister(disRef);
594: 
595:                 const rrVal = SettingsStore.getValue("sendReadReceipts", null, true);
596:                 if (typeof rrVal !== "boolean") {
597:                     // new setting isn't set - see if the labs flag was. We have to manually reach into the
598:                     // handler for this because it isn't a setting anymore (`getValue` will yell at us).
599:                     const handler = LEVEL_HANDLERS[SettingLevel.DEVICE] as DeviceSettingsHandler;
600:                     const labsVal = handler.readFeature("feature_hidden_read_receipts");
601:                     if (typeof labsVal === "boolean") {
602:                         // Inverse of labs flag because negative->positive language switch in setting name
603:                         const newVal = !labsVal;
604:                         console.log(`Setting sendReadReceipts to ${newVal} because of previously-set labs flag`);
605: 
606:                         // noinspection JSIgnoredPromiseFromCall
607:                         SettingsStore.setValue("sendReadReceipts", null, SettingLevel.ACCOUNT, newVal);
608:                     }
609:                 }
610:             }
611:         });
612:     }
613: 
614:     /**
615:      * Debugging function for reading explicit setting values without going through the
616:      * complicated/biased functions in the SettingsStore. This will print information to
617:      * the console for analysis. Not intended to be used within the application.
618:      * @param {string} realSettingName The setting name to try and read.
619:      * @param {string} roomId Optional room ID to test the setting in.
620:      */
621:     public static debugSetting(realSettingName: string, roomId: string) {
622:         logger.log(`--- DEBUG ${realSettingName}`);
623: 
624:         // Note: we intentionally use JSON.stringify here to avoid the console masking the
625:         // problem if there's a type representation issue. Also, this way it is guaranteed
626:         // to show up in a rageshake if required.
627: 
628:         const def = SETTINGS[realSettingName];
629:         logger.log(`--- definition: ${def ? JSON.stringify(def) : '<NOT_FOUND>'}`);
630:         logger.log(`--- default level order: ${JSON.stringify(LEVEL_ORDER)}`);
631:         logger.log(`--- registered handlers: ${JSON.stringify(Object.keys(LEVEL_HANDLERS))}`);
632: 
633:         const doChecks = (settingName) => {
634:             for (const handlerName of Object.keys(LEVEL_HANDLERS)) {
635:                 const handler = LEVEL_HANDLERS[handlerName];
636: 
637:                 try {
638:                     const value = handler.getValue(settingName, roomId);
639:                     logger.log(`---     ${handlerName}@${roomId || '<no_room>'} = ${JSON.stringify(value)}`);
640:                 } catch (e) {
641:                     logger.log(`---     ${handler}@${roomId || '<no_room>'} THREW ERROR: ${e.message}`);
642:                     logger.error(e);
643:                 }
644: 
645:                 if (roomId) {
646:                     try {
647:                         const value = handler.getValue(settingName, null);
648:                         logger.log(`---     ${handlerName}@<no_room> = ${JSON.stringify(value)}`);
649:                     } catch (e) {
650:                         logger.log(`---     ${handler}@<no_room> THREW ERROR: ${e.message}`);
651:                         logger.error(e);
652:                     }
653:                 }
654:             }
655: 
656:             logger.log(`--- calculating as returned by SettingsStore`);
657:             logger.log(`--- these might not match if the setting uses a controller - be warned!`);
658: 
659:             try {
660:                 const value = SettingsStore.getValue(settingName, roomId);
661:                 logger.log(`---     SettingsStore#generic@${roomId || '<no_room>'}  = ${JSON.stringify(value)}`);
662:             } catch (e) {
663:                 logger.log(`---     SettingsStore#generic@${roomId || '<no_room>'} THREW ERROR: ${e.message}`);
664:                 logger.error(e);
665:             }
666: 
667:             if (roomId) {
668:                 try {
669:                     const value = SettingsStore.getValue(settingName, null);
670:                     logger.log(`---     SettingsStore#generic@<no_room>  = ${JSON.stringify(value)}`);
671:                 } catch (e) {
672:                     logger.log(`---     SettingsStore#generic@$<no_room> THREW ERROR: ${e.message}`);
673:                     logger.error(e);
674:                 }
675:             }
676: 
677:             for (const level of LEVEL_ORDER) {
678:                 try {
679:                     const value = SettingsStore.getValueAt(level, settingName, roomId);
680:                     logger.log(`---     SettingsStore#${level}@${roomId || '<no_room>'} = ${JSON.stringify(value)}`);
681:                 } catch (e) {
682:                     logger.log(`---     SettingsStore#${level}@${roomId || '<no_room>'} THREW ERROR: ${e.message}`);
683:                     logger.error(e);
684:                 }
685: 
686:                 if (roomId) {
687:                     try {
688:                         const value = SettingsStore.getValueAt(level, settingName, null);
689:                         logger.log(`---     SettingsStore#${level}@<no_room> = ${JSON.stringify(value)}`);
690:                     } catch (e) {
691:                         logger.log(`---     SettingsStore#${level}@$<no_room> THREW ERROR: ${e.message}`);
692:                         logger.error(e);
693:                     }
694:                 }
695:             }
696:         };
697: 
698:         doChecks(realSettingName);
699: 
700:         if (def.invertedSettingName) {
701:             logger.log(`--- TESTING INVERTED SETTING NAME`);
702:             logger.log(`--- inverted: ${def.invertedSettingName}`);
703:             doChecks(def.invertedSettingName);
704:         }
705: 
706:         logger.log(`--- END DEBUG`);
707:     }
708: 
709:     private static getHandler(settingName: string, level: SettingLevel): SettingsHandler {
710:         const handlers = SettingsStore.getHandlers(settingName);
711:         if (!handlers[level]) return null;
712:         return handlers[level];
713:     }
714: 
715:     private static getHandlers(settingName: string): IHandlerMap {
716:         if (!SETTINGS[settingName]) return {};
717: 
718:         const handlers = {};
719:         for (const level of SETTINGS[settingName].supportedLevels) {
720:             if (!LEVEL_HANDLERS[level]) throw new Error("Unexpected level " + level);
721:             if (SettingsStore.isLevelSupported(level)) handlers[level] = LEVEL_HANDLERS[level];
722:         }
723: 
724:         // Always support 'default'
725:         if (!handlers['default']) handlers['default'] = LEVEL_HANDLERS['default'];
726: 
727:         return handlers;
728:     }
729: }
730: 
731: // For debugging purposes
732: window.mxSettingsStore = SettingsStore;
