48:     public getThreadRoomState(thread: Thread): ThreadNotificationState {
49:         if (!this.threadsState.has(thread)) {
50:             this.threadsState.set(thread, new ThreadNotificationState(thread));
51:         }
52:         return this.threadsState.get(thread);
53:     }
54: 
55:     private onNewThread = (thread: Thread): void => {
56:         const notificationState = new ThreadNotificationState(thread);
57:         this.threadsState.set(
58:             thread,
59:             notificationState,
60:         );
61:         notificationState.on(NotificationStateEvents.Update, this.onThreadUpdate);
62:     };
