243: /**
244:  * Create an Event.
245:  * @param {Object} opts Values for the event.
246:  * @param {string} opts.type The event.type
247:  * @param {string} opts.room The event.room_id
248:  * @param {string} opts.user The event.user_id
249:  * @param {string=} opts.skey Optional. The state key (auto inserts empty string)
250:  * @param {number=} opts.ts   Optional. Timestamp for the event
251:  * @param {Object} opts.content The event.content
252:  * @param {boolean} opts.event True to make a MatrixEvent.
253:  * @param {unsigned=} opts.unsigned
254:  * @return {Object} a JSON object representing this event.
255:  */
256: export function mkEvent(opts: MakeEventProps): MatrixEvent {
257:     if (!opts.type || !opts.content) {
258:         throw new Error("Missing .type or .content =>" + JSON.stringify(opts));
259:     }
260:     const event: Partial<IEvent> = {
261:         type: opts.type,
262:         room_id: opts.room,
263:         sender: opts.user,
264:         content: opts.content,
265:         prev_content: opts.prev_content,
266:         event_id: "$" + Math.random() + "-" + Math.random(),
267:         origin_server_ts: opts.ts ?? 0,
268:         unsigned: opts.unsigned,
269:         redacts: opts.redacts,
270:     };
271:     if (opts.skey !== undefined) {
272:         event.state_key = opts.skey;
273:     } else if ([
274:         "m.room.name", "m.room.topic", "m.room.create", "m.room.join_rules",
275:         "m.room.power_levels", "m.room.topic", "m.room.history_visibility",
276:         "m.room.encryption", "m.room.member", "com.example.state",
277:         "m.room.guest_access", "m.room.tombstone",
278:     ].indexOf(opts.type) !== -1) {
279:         event.state_key = "";
280:     }
281: 
282:     const mxEvent = opts.event ? new MatrixEvent(event) : event as unknown as MatrixEvent;
283:     if (!mxEvent.sender && opts.user && opts.room) {
284:         mxEvent.sender = {
285:             userId: opts.user,
286:             membership: "join",
287:             name: opts.user,
288:             rawDisplayName: opts.user,
289:             roomId: opts.room,
290:             getAvatarUrl: () => {},
291:             getMxcAvatarUrl: () => {},
292:         } as unknown as RoomMember;
293:     }
294:     return mxEvent;
295: }
