361:     }
362:     if (opts.name) { event.content.displayname = opts.name; }
363:     if (opts.url) { event.content.avatar_url = opts.url; }
364:     const e = mkEvent(event);
365:     if (opts.target) {
366:         e.target = opts.target;
367:     }
368:     return e;
369: }
