517: export const mockStateEventImplementation = (events: MatrixEvent[]) => {
518:     const stateMap = new EnhancedMap<string, Map<string, MatrixEvent>>();
519:     events.forEach(event => {
520:         stateMap.getOrCreate(event.getType(), new Map()).set(event.getStateKey(), event);
521:     });
522: 
523:     // recreate the overloading in RoomState
524:     function getStateEvents(eventType: EventType | string): MatrixEvent[];
525:     function getStateEvents(eventType: EventType | string, stateKey: string): MatrixEvent;
526:     function getStateEvents(eventType: EventType | string, stateKey?: string) {
527:         if (stateKey || stateKey === "") {
528:             return stateMap.get(eventType)?.get(stateKey) || null;
529:         }
530:         return Array.from(stateMap.get(eventType)?.values() || []);
531:     }
532:     return getStateEvents;
533: };
