89:     /**
90:      * Returns true if the current user has just been registered by this
91:      * client as determined by setJustRegisteredUserId()
92:      *
93:      * @returns {bool} True if user has just been registered
94:      */
95:     currentUserIsJustRegistered(): boolean;
96: 
97:     /**
98:      * If the current user has been registered by this device then this
99:      * returns a boolean of whether it was within the last N hours given.
100:      */
101:     userRegisteredWithinLastHours(hours: number): boolean;
102: 
103:     /**
104:      * If the current user has been registered by this device then this
105:      * returns a boolean of whether it was after a given timestamp.
106:      */
107:     userRegisteredAfter(date: Date): boolean;
108: 
109:     /**
110:      * Replace this MatrixClientPeg's client with a client instance that has
111:      * homeserver / identity server URLs and active credentials
112:      *
113:      * @param {IMatrixClientCreds} creds The new credentials to use.
114:      */
115:     replaceUsingCreds(creds: IMatrixClientCreds): void;
116: }
117: 
118: /**
119:  * Wrapper object for handling the js-sdk Matrix Client object in the react-sdk
120:  * Handles the creation/initialisation of client objects.
121:  * This module provides a singleton instance of this class so the 'current'
122:  * Matrix Client object is available easily.
123:  */
124: class MatrixClientPegClass implements IMatrixClientPeg {
125:     // These are the default options used when when the
126:     // client is started in 'start'. These can be altered
127:     // at any time up to after the 'will_start_client'
128:     // event is finished processing.
129:     public opts: IStartClientOpts = {
130:         initialSyncLimit: 20,
131:     };
132: 
133:     private matrixClient: MatrixClient = null;
134:     private justRegisteredUserId: string | null = null;
135: 
136:     // the credentials used to init the current client object.
137:     // used if we tear it down & recreate it with a different store
138:     private currentClientCreds: IMatrixClientCreds;
139: 
140:     public get(): MatrixClient {
141:         return this.matrixClient;
142:     }
143: 
144:     public unset(): void {
145:         this.matrixClient = null;
146: 
147:         MatrixActionCreators.stop();
148:     }
149: 
150:     public setJustRegisteredUserId(uid: string | null): void {
151:         this.justRegisteredUserId = uid;
152:         if (uid) {
153:             const registrationTime = Date.now().toString();
154:             window.localStorage.setItem("mx_registration_time", registrationTime);
155:         }
156:     }
157: 
158:     public currentUserIsJustRegistered(): boolean {
159:         return (
160:             this.matrixClient &&
161:             this.matrixClient.credentials.userId === this.justRegisteredUserId
162:         );
163:     }
164: 
165:     public userRegisteredWithinLastHours(hours: number): boolean {
166:         if (hours <= 0) {
167:             return false;
168:         }
169: 
170:         try {
171:             const registrationTime = parseInt(window.localStorage.getItem("mx_registration_time"), 10);
172:             const diff = Date.now() - registrationTime;
173:             return (diff / 36e5) <= hours;
174:         } catch (e) {
175:             return false;
176:         }
177:     }
178: 
179:     public userRegisteredAfter(timestamp: Date): boolean {
180:         try {
181:             const registrationTime = parseInt(window.localStorage.getItem("mx_registration_time"), 10);
182:             return timestamp.getTime() <= registrationTime;
183:         } catch (e) {
184:             return false;
185:         }
186:     }
187: 
188:     public replaceUsingCreds(creds: IMatrixClientCreds): void {
189:         this.currentClientCreds = creds;
190:         this.createClient(creds);
191:     }
192: 
193:     public async assign(): Promise<any> {
194:         for (const dbType of ['indexeddb', 'memory']) {
195:             try {
196:                 const promise = this.matrixClient.store.startup();
197:                 logger.log("MatrixClientPeg: waiting for MatrixClient store to initialise");
198:                 await promise;
199:                 break;
200:             } catch (err) {
201:                 if (dbType === 'indexeddb') {
202:                     logger.error('Error starting matrixclient store - falling back to memory store', err);
203:                     this.matrixClient.store = new MemoryStore({
204:                         localStorage: localStorage,
205:                     });
206:                 } else {
207:                     logger.error('Failed to start memory store!', err);
208:                     throw err;
209:                 }
210:             }
211:         }
212: 
213:         // try to initialise e2e on the new client
214:         try {
215:             // check that we have a version of the js-sdk which includes initCrypto
216:             if (!SettingsStore.getValue("lowBandwidth") && this.matrixClient.initCrypto) {
217:                 await this.matrixClient.initCrypto();
218:                 this.matrixClient.setCryptoTrustCrossSignedDevices(
219:                     !SettingsStore.getValue('e2ee.manuallyVerifyAllSessions'),
220:                 );
221:                 await tryToUnlockSecretStorageWithDehydrationKey(this.matrixClient);
222:                 StorageManager.setCryptoInitialised(true);
223:             }
224:         } catch (e) {
225:             if (e && e.name === 'InvalidCryptoStoreError') {
226:                 // The js-sdk found a crypto DB too new for it to use
227:                 Modal.createDialog(CryptoStoreTooNewDialog);
228:             }
229:             // this can happen for a number of reasons, the most likely being
230:             // that the olm library was missing. It's not fatal.
231:             logger.warn("Unable to initialise e2e", e);
232:         }
233: 
234:         const opts = utils.deepCopy(this.opts);
235:         // the react sdk doesn't work without this, so don't allow
236:         opts.pendingEventOrdering = PendingEventOrdering.Detached;
237:         opts.lazyLoadMembers = true;
238:         opts.clientWellKnownPollPeriod = 2 * 60 * 60; // 2 hours
239:         opts.experimentalThreadSupport = SettingsStore.getValue("feature_thread");
240: 
241:         if (SettingsStore.getValue("feature_sliding_sync")) {
242:             const proxyUrl = SettingsStore.getValue("feature_sliding_sync_proxy_url");
243:             if (proxyUrl) {
244:                 logger.log("Activating sliding sync using proxy at ", proxyUrl);
245:             } else {
246:                 logger.log("Activating sliding sync");
247:             }
248:             opts.slidingSync = SlidingSyncManager.instance.configure(
249:                 this.matrixClient,
250:                 proxyUrl || this.matrixClient.baseUrl,
251:             );
252:             SlidingSyncManager.instance.startSpidering(100, 50); // 100 rooms at a time, 50ms apart
253:         }
254: 
255:         // Connect the matrix client to the dispatcher and setting handlers
256:         MatrixActionCreators.start(this.matrixClient);
257:         MatrixClientBackedSettingsHandler.matrixClient = this.matrixClient;
258: 
259:         return opts;
260:     }
261: 
262:     public async start(): Promise<any> {
263:         const opts = await this.assign();
264: 
265:         logger.log(`MatrixClientPeg: really starting MatrixClient`);
266:         await this.get().startClient(opts);
267:         logger.log(`MatrixClientPeg: MatrixClient started`);
268:     }
269: 
270:     public getCredentials(): IMatrixClientCreds {
271:         let copiedCredentials = this.currentClientCreds;
272:         if (this.currentClientCreds?.userId !== this.matrixClient?.credentials?.userId) {
273:             // cached credentials belong to a different user - don't use them
274:             copiedCredentials = null;
275:         }
276:         return {
277:             // Copy the cached credentials before overriding what we can.
278:             ...(copiedCredentials ?? {}),
279: 
280:             homeserverUrl: this.matrixClient.baseUrl,
281:             identityServerUrl: this.matrixClient.idBaseUrl,
282:             userId: this.matrixClient.credentials.userId,
283:             deviceId: this.matrixClient.getDeviceId(),
284:             accessToken: this.matrixClient.getAccessToken(),
285:             guest: this.matrixClient.isGuest(),
286:         };
287:     }
288: 
289:     public getHomeserverName(): string {
290:         const matches = /^@[^:]+:(.+)$/.exec(this.matrixClient.credentials.userId);
291:         if (matches === null || matches.length < 1) {
292:             throw new Error("Failed to derive homeserver name from user ID!");
293:         }
294:         return matches[1];
295:     }
296: 
297:     private namesToRoomName(names: string[], count: number): string | undefined {
298:         const countWithoutMe = count - 1;
299:         if (!names.length) {
300:             return _t("Empty room");
301:         }
302:         if (names.length === 1 && countWithoutMe <= 1) {
303:             return names[0];
304:         }
305:     }
306: 
307:     private memberNamesToRoomName(names: string[], count: number): string {
308:         const name = this.namesToRoomName(names, count);
309:         if (name) return name;
310: 
311:         if (names.length === 2 && count === 2) {
312:             return _t("%(user1)s and %(user2)s", {
313:                 user1: names[0],
314:                 user2: names[1],
315:             });
316:         }
317:         return _t("%(user)s and %(count)s others", {
318:             user: names[0],
319:             count: count - 1,
320:         });
321:     }
322: 
323:     private inviteeNamesToRoomName(names: string[], count: number): string {
324:         const name = this.namesToRoomName(names, count);
325:         if (name) return name;
326: 
327:         if (names.length === 2 && count === 2) {
328:             return _t("Inviting %(user1)s and %(user2)s", {
329:                 user1: names[0],
330:                 user2: names[1],
331:             });
332:         }
333:         return _t("Inviting %(user)s and %(count)s others", {
334:             user: names[0],
335:             count: count - 1,
336:         });
337:     }
338: 
339:     private createClient(creds: IMatrixClientCreds): void {
340:         const opts: ICreateClientOpts = {
341:             baseUrl: creds.homeserverUrl,
342:             idBaseUrl: creds.identityServerUrl,
343:             accessToken: creds.accessToken,
344:             userId: creds.userId,
345:             deviceId: creds.deviceId,
346:             pickleKey: creds.pickleKey,
347:             timelineSupport: true,
348:             forceTURN: !SettingsStore.getValue('webRtcAllowPeerToPeer'),
349:             fallbackICEServerAllowed: !!SettingsStore.getValue('fallbackICEServerAllowed'),
350:             // Gather up to 20 ICE candidates when a call arrives: this should be more than we'd
351:             // ever normally need, so effectively this should make all the gathering happen when
352:             // the call arrives.
353:             iceCandidatePoolSize: 20,
354:             verificationMethods: [
355:                 verificationMethods.SAS,
356:                 SHOW_QR_CODE_METHOD,
357:                 verificationMethods.RECIPROCATE_QR_CODE,
358:             ],
359:             identityServer: new IdentityAuthClient(),
360:             // These are always installed regardless of the labs flag so that cross-signing features
361:             // can toggle on without reloading and also be accessed immediately after login.
362:             cryptoCallbacks: { ...crossSigningCallbacks },
363:             roomNameGenerator: (_: string, state: RoomNameState) => {
364:                 switch (state.type) {
365:                     case RoomNameType.Generated:
366:                         switch (state.subtype) {
367:                             case "Inviting":
368:                                 return this.inviteeNamesToRoomName(state.names, state.count);
369:                             default:
370:                                 return this.memberNamesToRoomName(state.names, state.count);
371:                         }
372:                     case RoomNameType.EmptyRoom:
373:                         if (state.oldName) {
374:                             return _t("Empty room (was %(oldName)s)", {
375:                                 oldName: state.oldName,
376:                             });
377:                         } else {
378:                             return _t("Empty room");
379:                         }
380:                     default:
381:                         return null;
382:                 }
383:             },
384:         };
385: 
386:         if (SecurityCustomisations.getDehydrationKey) {
387:             opts.cryptoCallbacks!.getDehydrationKey = SecurityCustomisations.getDehydrationKey;
388:         }
389: 
390:         this.matrixClient = createMatrixClient(opts);
391: 
392:         // we're going to add eventlisteners for each matrix event tile, so the
393:         // potential number of event listeners is quite high.
394:         this.matrixClient.setMaxListeners(500);
395: 
396:         this.matrixClient.setGuest(Boolean(creds.guest));
397: 
398:         const notifTimelineSet = new EventTimelineSet(undefined, {
399:             timelineSupport: true,
400:             pendingEvents: false,
401:         });
402:         // XXX: what is our initial pagination token?! it somehow needs to be synchronised with /sync.
403:         notifTimelineSet.getLiveTimeline().setPaginationToken("", EventTimeline.BACKWARDS);
404:         this.matrixClient.setNotifTimelineSet(notifTimelineSet);
405:     }
406: }
407: 
408: /**
409:  * Note: You should be using a React context with access to a client rather than
410:  * using this, as in a multi-account world this will not exist!
411:  */
412: export const MatrixClientPeg: IMatrixClientPeg = new MatrixClientPegClass();
413: 
414: if (!window.mxMatrixClientPeg) {
415:     window.mxMatrixClientPeg = MatrixClientPeg;
416: }
