17: import { logger } from "matrix-js-sdk/src/logger";
18: import { CryptoEvent } from "matrix-js-sdk/src/crypto";
19: import { Optional } from "matrix-events-sdk";
20: 
21: import defaultDispatcher from '../../dispatcher/dispatcher';
22: import { pendingVerificationRequestForUser } from '../../verification';
23: import SettingsStore from "../../settings/SettingsStore";
24: import { RightPanelPhases } from "./RightPanelStorePhases";
25: import { SettingLevel } from "../../settings/SettingLevel";
26: import { UPDATE_EVENT } from '../AsyncStore';
27: import { ReadyWatchingStore } from '../ReadyWatchingStore';
28: import {
29:     convertToStatePanel,
30:     convertToStorePanel,
31:     IRightPanelCard,
32:     IRightPanelForRoom,
33: } from './RightPanelStoreIPanelState';
34: import { ActionPayload } from "../../dispatcher/payloads";
35: import { Action } from "../../dispatcher/actions";
36: import { ActiveRoomChangedPayload } from "../../dispatcher/payloads/ActiveRoomChangedPayload";
37: import { SdkContextClass } from "../../contexts/SDKContext";
38: 
39: /**
40:  * A class for tracking the state of the right panel between layouts and
41:  * sessions. This state includes a history for each room. Each history element
42:  * contains the phase (e.g. RightPanelPhase.RoomMemberInfo) and the state (e.g.
43:  * the member) associated with it.
44: */
45: export default class RightPanelStore extends ReadyWatchingStore {
46:     private static internalInstance: RightPanelStore;
47: 
48:     private global?: IRightPanelForRoom;
49:     private byRoom: { [roomId: string]: IRightPanelForRoom };
50:     private viewedRoomId: Optional<string>;
51: 
52:     private constructor() {
53:         super(defaultDispatcher);
54:         this.reset();
55:     }
56: 
57:     /**
58:      * Resets the store. Intended for test usage only.
59:      */
60:     public reset() {
61:         this.global = null;
62:         this.byRoom = {};
63:         this.viewedRoomId = null;
64:     }
65: 
66:     protected async onReady(): Promise<any> {
67:         this.viewedRoomId = SdkContextClass.instance.roomViewStore.getRoomId();
68:         this.matrixClient.on(CryptoEvent.VerificationRequest, this.onVerificationRequestUpdate);
69:         this.loadCacheFromSettings();
70:         this.emitAndUpdateSettings();
71:     }
72: 
73:     protected async onNotReady(): Promise<any> {
74:         this.matrixClient.off(CryptoEvent.VerificationRequest, this.onVerificationRequestUpdate);
75:     }
76: 
77:     protected onDispatcherAction(payload: ActionPayload) {
78:         if (payload.action !== Action.ActiveRoomChanged) return;
79: 
80:         const changePayload = <ActiveRoomChangedPayload>payload;
81:         this.handleViewedRoomChange(changePayload.oldRoomId, changePayload.newRoomId);
82:     }
83: 
84:     // Getters
85:     /**
86:      * If you are calling this from a component that already knows about a
87:      * specific room from props / state, then it's best to prefer
88:      * `isOpenForRoom` below to ensure all your data is for a single room
89:      * during room changes.
90:      */
91:     public get isOpen(): boolean {
92:         return this.byRoom[this.viewedRoomId]?.isOpen ?? false;
93:     }
94: 
95:     public isOpenForRoom(roomId: string): boolean {
96:         return this.byRoom[roomId]?.isOpen ?? false;
97:     }
98: 
99:     public get roomPhaseHistory(): Array<IRightPanelCard> {
100:         return this.byRoom[this.viewedRoomId]?.history ?? [];
101:     }
102: 
103:     /**
104:      * If you are calling this from a component that already knows about a
105:      * specific room from props / state, then it's best to prefer
106:      * `currentCardForRoom` below to ensure all your data is for a single room
107:      * during room changes.
108:      */
109:     public get currentCard(): IRightPanelCard {
110:         const hist = this.roomPhaseHistory;
111:         if (hist.length >= 1) {
112:             return hist[hist.length - 1];
113:         }
114:         return { state: {}, phase: null };
115:     }
116: 
117:     public currentCardForRoom(roomId: string): IRightPanelCard {
118:         const hist = this.byRoom[roomId]?.history ?? [];
119:         if (hist.length > 0) {
120:             return hist[hist.length - 1];
121:         }
122:         return { state: {}, phase: null };
123:     }
124: 
125:     public get previousCard(): IRightPanelCard {
126:         const hist = this.roomPhaseHistory;
127:         if (hist?.length >= 2) {
128:             return hist[hist.length - 2];
129:         }
130:         return { state: {}, phase: null };
131:     }
132: 
133:     // Setters
134:     public setCard(card: IRightPanelCard, allowClose = true, roomId?: string) {
135:         const rId = roomId ?? this.viewedRoomId;
136:         // This function behaves as following:
137:         // Update state: if the same phase is send but with a state
138:         // Set right panel and erase history: if a "different to the current" phase is send (with or without a state)
139:         // If the right panel is set, this function also shows the right panel.
140:         const redirect = this.getVerificationRedirect(card);
141:         const targetPhase = redirect?.phase ?? card.phase;
142:         const cardState = redirect?.state ?? (Object.keys(card.state ?? {}).length === 0 ? null : card.state);
143: 
144:         // Checks for wrong SetRightPanelPhase requests
145:         if (!this.isPhaseValid(targetPhase, Boolean(rId))) return;
146: 
147:         if ((targetPhase === this.currentCardForRoom(rId)?.phase && !!cardState)) {
148:             // Update state: set right panel with a new state but keep the phase (don't know it this is ever needed...)
149:             const hist = this.byRoom[rId]?.history ?? [];
150:             hist[hist.length - 1].state = cardState;
151:             this.emitAndUpdateSettings();
152:         } else if (targetPhase !== this.currentCardForRoom(rId)?.phase || !this.byRoom[rId]) {
153:             // Set right panel and initialize/erase history
154:             const history = [{ phase: targetPhase, state: cardState ?? {} }];
155:             this.byRoom[rId] = { history, isOpen: true };
156:             this.emitAndUpdateSettings();
157:         } else {
158:             this.show(rId);
159:             this.emitAndUpdateSettings();
160:         }
161:     }
162: 
163:     public setCards(cards: IRightPanelCard[], allowClose = true, roomId: string = null) {
164:         // This function sets the history of the right panel and shows the right panel if not already visible.
165:         const rId = roomId ?? this.viewedRoomId;
166:         const history = cards.map(c => ({ phase: c.phase, state: c.state ?? {} }));
167:         this.byRoom[rId] = { history, isOpen: true };
168:         this.show(rId);
169:         this.emitAndUpdateSettings();
170:     }
171: 
172:     // Appends a card to the history and shows the right panel if not already visible
173:     public pushCard(
174:         card: IRightPanelCard,
175:         allowClose = true,
176:         roomId: string = null,
177:     ) {
178:         const rId = roomId ?? this.viewedRoomId;
179:         const redirect = this.getVerificationRedirect(card);
180:         const targetPhase = redirect?.phase ?? card.phase;
181:         const pState = redirect?.state ?? card.state ?? {};
182: 
183:         // Checks for wrong SetRightPanelPhase requests
184:         if (!this.isPhaseValid(targetPhase, Boolean(rId))) return;
185: 
186:         const roomCache = this.byRoom[rId];
187:         if (!!roomCache) {
188:             // append new phase
189:             roomCache.history.push({ state: pState, phase: targetPhase });
190:             roomCache.isOpen = allowClose ? roomCache.isOpen : true;
191:         } else {
192:             // setup room panel cache with the new card
193:             this.byRoom[rId] = {
194:                 history: [{ phase: targetPhase, state: pState }],
195:                 // if there was no right panel store object the the panel was closed -> keep it closed, except if allowClose==false
196:                 isOpen: !allowClose,
197:             };
198:         }
199:         this.show(rId);
200:         this.emitAndUpdateSettings();
201:     }
202: 
203:     public popCard(roomId: string = null) {
204:         const rId = roomId ?? this.viewedRoomId;
205:         if (!this.byRoom[rId]) return;
206: 
207:         const removedCard = this.byRoom[rId].history.pop();
208:         this.emitAndUpdateSettings();
209:         return removedCard;
210:     }
211: 
212:     public togglePanel(roomId: string | null) {
213:         const rId = roomId ?? this.viewedRoomId;
214:         if (!this.byRoom[rId]) return;
215: 
216:         this.byRoom[rId].isOpen = !this.byRoom[rId].isOpen;
217:         this.emitAndUpdateSettings();
218:     }
219: 
220:     public show(roomId: string | null) {
221:         if (!this.isOpenForRoom(roomId ?? this.viewedRoomId)) {
222:             this.togglePanel(roomId);
223:         }
224:     }
225: 
226:     public hide(roomId: string | null) {
227:         if (this.isOpenForRoom(roomId ?? this.viewedRoomId)) {
228:             this.togglePanel(roomId);
229:         }
230:     }
231: 
232:     private loadCacheFromSettings() {
233:         if (this.viewedRoomId) {
234:             const room = this.mxClient?.getRoom(this.viewedRoomId);
235:             if (!!room) {
236:                 this.global = this.global ??
237:                     convertToStatePanel(SettingsStore.getValue("RightPanel.phasesGlobal"), room);
238:                 this.byRoom[this.viewedRoomId] = this.byRoom[this.viewedRoomId] ??
239:                     convertToStatePanel(SettingsStore.getValue("RightPanel.phases", this.viewedRoomId), room);
240:             } else {
241:                 logger.warn(
242:                     "Could not restore the right panel after load because there was no associated room object.",
243:                 );
244:             }
245:         }
246:     }
247: 
248:     private emitAndUpdateSettings() {
249:         this.filterValidCards(this.global);
250:         const storePanelGlobal = convertToStorePanel(this.global);
251:         SettingsStore.setValue("RightPanel.phasesGlobal", null, SettingLevel.DEVICE, storePanelGlobal);
252: 
253:         if (!!this.viewedRoomId) {
254:             const panelThisRoom = this.byRoom[this.viewedRoomId];
255:             this.filterValidCards(panelThisRoom);
256:             const storePanelThisRoom = convertToStorePanel(panelThisRoom);
257:             SettingsStore.setValue(
258:                 "RightPanel.phases",
259:                 this.viewedRoomId,
260:                 SettingLevel.ROOM_DEVICE,
261:                 storePanelThisRoom,
262:             );
263:         }
264:         this.emit(UPDATE_EVENT, null);
265:     }
266: 
267:     private filterValidCards(rightPanelForRoom?: IRightPanelForRoom) {
268:         if (!rightPanelForRoom?.history) return;
269:         rightPanelForRoom.history = rightPanelForRoom.history.filter((card) => this.isCardStateValid(card));
270:         if (!rightPanelForRoom.history.length) {
271:             rightPanelForRoom.isOpen = false;
272:         }
273:     }
274: 
275:     private isCardStateValid(card: IRightPanelCard) {
276:         // this function does a sanity check on the card. this is required because
277:         // some phases require specific state properties that might not be available.
278:         // This can be caused on if element is reloaded and the tries to reload right panel data from id's stored in the local storage.
279:         // we store id's of users and matrix events. If are not yet fetched on reload the right panel cannot display them.
280:         // or potentially other errors.
281:         // (A nicer fix could be to indicate, that the right panel is loading if there is missing state data and re-emit if the data is available)
282:         switch (card.phase) {
283:             case RightPanelPhases.ThreadPanel:
284:                 if (!SettingsStore.getValue("feature_thread")) return false;
285:                 break;
286:             case RightPanelPhases.ThreadView:
287:                 if (!SettingsStore.getValue("feature_thread")) return false;
288:                 if (!card.state.threadHeadEvent) {
289:                     logger.warn("removed card from right panel because of missing threadHeadEvent in card state");
290:                 }
291:                 return !!card.state.threadHeadEvent;
292:             case RightPanelPhases.RoomMemberInfo:
293:             case RightPanelPhases.SpaceMemberInfo:
294:             case RightPanelPhases.EncryptionPanel:
295:                 if (!card.state.member) {
296:                     logger.warn("removed card from right panel because of missing member in card state");
297:                 }
298:                 return !!card.state.member;
299:             case RightPanelPhases.Room3pidMemberInfo:
300:             case RightPanelPhases.Space3pidMemberInfo:
301:                 if (!card.state.memberInfoEvent) {
302:                     logger.warn("removed card from right panel because of missing memberInfoEvent in card state");
303:                 }
304:                 return !!card.state.memberInfoEvent;
305:             case RightPanelPhases.Widget:
306:                 if (!card.state.widgetId) {
307:                     logger.warn("removed card from right panel because of missing widgetId in card state");
308:                 }
309:                 return !!card.state.widgetId;
310:         }
311:         return true;
312:     }
313: 
314:     private getVerificationRedirect(card: IRightPanelCard): IRightPanelCard {
315:         if (card.phase === RightPanelPhases.RoomMemberInfo && card.state) {
316:             // RightPanelPhases.RoomMemberInfo -> needs to be changed to RightPanelPhases.EncryptionPanel if there is a pending verification request
317:             const { member } = card.state;
318:             const pendingRequest = pendingVerificationRequestForUser(member);
319:             if (pendingRequest) {
320:                 return {
321:                     phase: RightPanelPhases.EncryptionPanel,
322:                     state: {
323:                         verificationRequest: pendingRequest,
324:                         member,
325:                     },
326:                 };
327:             }
328:         }
329:         return null;
330:     }
331: 
332:     private isPhaseValid(targetPhase: RightPanelPhases, isViewingRoom: boolean): boolean {
333:         if (!RightPanelPhases[targetPhase]) {
334:             logger.warn(`Tried to switch right panel to unknown phase: ${targetPhase}`);
335:             return false;
336:         }
337:         if (!isViewingRoom) {
338:             logger.warn(
339:                 `Tried to switch right panel to a room phase: ${targetPhase}, ` +
340:                 `but we are currently not viewing a room`,
341:             );
342:             return false;
343:         }
344:         return true;
345:     }
346: 
347:     private onVerificationRequestUpdate = () => {
348:         if (!this.currentCard?.state) return;
349:         const { member } = this.currentCard.state;
350:         if (!member) return;
351:         const pendingRequest = pendingVerificationRequestForUser(member);
352:         if (pendingRequest) {
353:             this.currentCard.state.verificationRequest = pendingRequest;
354:             this.emitAndUpdateSettings();
355:         }
356:     };
357: 
358:     private handleViewedRoomChange(oldRoomId: Optional<string>, newRoomId: Optional<string>) {
359:         if (!this.mxClient) return; // not ready, onReady will handle the first room
360:         this.viewedRoomId = newRoomId;
361:         // load values from byRoomCache with the viewedRoomId.
362:         this.loadCacheFromSettings();
363: 
364:         // when we're switching to a room, clear out any stale MemberInfo cards
365:         // in order to fix https://github.com/vector-im/element-web/issues/21487
366:         if (this.currentCard?.phase !== RightPanelPhases.EncryptionPanel) {
367:             const panel = this.byRoom[this.viewedRoomId];
368:             if (panel?.history) {
369:                 panel.history = panel.history.filter(
370:                     (card) => card.phase != RightPanelPhases.RoomMemberInfo &&
371:                         card.phase != RightPanelPhases.Room3pidMemberInfo,
372:                 );
373:             }
374:         }
375: 
376:         // If the right panel stays open mode is used, and the panel was either
377:         // closed or never shown for that room, then force it open and display
378:         // the room member list.
379:         if (
380:             SettingsStore.getValue("feature_right_panel_default_open") &&
381:             !this.byRoom[this.viewedRoomId]?.isOpen
382:         ) {
383:             const history = [{ phase: RightPanelPhases.RoomMemberList }];
384:             const room = this.viewedRoomId && this.mxClient?.getRoom(this.viewedRoomId);
385:             if (!room?.isSpaceRoom()) {
386:                 history.unshift({ phase: RightPanelPhases.RoomSummary });
387:             }
388:             this.byRoom[this.viewedRoomId] = {
389:                 isOpen: true,
390:                 history,
391:             };
392:         }
393:         this.emitAndUpdateSettings();
394:     }
395: 
396:     public static get instance(): RightPanelStore {
397:         if (!this.internalInstance) {
398:             this.internalInstance = new RightPanelStore();
399:             this.internalInstance.start();
400:         }
401:         return this.internalInstance;
402:     }
403: }
