25: export interface IRightPanelCardState {
26:     member?: RoomMember | User;
27:     verificationRequest?: VerificationRequest;
28:     verificationRequestPromise?: Promise<VerificationRequest>;
29:     widgetId?: string;
30:     spaceId?: string;
31:     // Room3pidMemberInfo, Space3pidMemberInfo,
32:     memberInfoEvent?: MatrixEvent;
33:     // threads
34:     threadHeadEvent?: MatrixEvent;
35:     initialEvent?: MatrixEvent;
36:     isInitialEventHighlighted?: boolean;
37:     initialEventScrollIntoView?: boolean;
38: }
39: 
40: export interface IRightPanelCardStateStored {
41:     memberId?: string;
42:     // we do not store the things associated with verification
43:     widgetId?: string;
44:     spaceId?: string;
45:     // 3pidMemberInfo
46:     memberInfoEventId?: string;
47:     // threads
48:     threadHeadEventId?: string;
49:     initialEventId?: string;
50:     isInitialEventHighlighted?: boolean;
51:     initialEventScrollIntoView?: boolean;
52: }
