54: export interface IRightPanelCard {
55:     phase: RightPanelPhases;
56:     state?: IRightPanelCardState;
57: }
58: 
59: export interface IRightPanelCardStored {
60:     phase: RightPanelPhases;
61:     state?: IRightPanelCardStateStored;
62: }
63: 
64: export interface IRightPanelForRoom {
65:     isOpen: boolean;
66:     history: Array<IRightPanelCard>;
67: }
68: 
69: interface IRightPanelForRoomStored {
70:     isOpen: boolean;
71:     history: Array<IRightPanelCardStored>;
72: }
73: 
74: export function convertToStorePanel(cacheRoom: IRightPanelForRoom): IRightPanelForRoomStored {
75:     if (!cacheRoom) return cacheRoom;
76:     const storeHistory = [...cacheRoom.history].map(panelState => convertCardToStore(panelState));
77:     return { isOpen: cacheRoom.isOpen, history: storeHistory };
78: }
79: 
80: export function convertToStatePanel(storeRoom: IRightPanelForRoomStored, room: Room): IRightPanelForRoom {
81:     if (!storeRoom) return storeRoom;
82:     const stateHistory = [...storeRoom.history].map(panelStateStore => convertStoreToCard(panelStateStore, room));
83:     return { history: stateHistory, isOpen: storeRoom.isOpen };
84: }
85: 
86: export function convertCardToStore(panelState: IRightPanelCard): IRightPanelCardStored {
87:     const state = panelState.state ?? {};
88:     const stateStored: IRightPanelCardStateStored = {
89:         widgetId: state.widgetId,
90:         spaceId: state.spaceId,
91:         isInitialEventHighlighted: state.isInitialEventHighlighted,
92:         initialEventScrollIntoView: state.initialEventScrollIntoView,
93:         threadHeadEventId: !!state?.threadHeadEvent?.getId() ?
94:             panelState.state.threadHeadEvent.getId() : undefined,
95:         memberInfoEventId: !!state?.memberInfoEvent?.getId() ?
96:             panelState.state.memberInfoEvent.getId() : undefined,
97:         initialEventId: !!state?.initialEvent?.getId() ?
98:             panelState.state.initialEvent.getId() : undefined,
99:         memberId: !!state?.member?.userId ?
100:             panelState.state.member.userId : undefined,
101:     };
102: 
103:     return { state: stateStored, phase: panelState.phase };
104: }
105: 
106: function convertStoreToCard(panelStateStore: IRightPanelCardStored, room: Room): IRightPanelCard {
107:     const stateStored = panelStateStore.state ?? {};
108:     const state: IRightPanelCardState = {
109:         widgetId: stateStored.widgetId,
110:         spaceId: stateStored.spaceId,
111:         isInitialEventHighlighted: stateStored.isInitialEventHighlighted,
112:         initialEventScrollIntoView: stateStored.initialEventScrollIntoView,
113:         threadHeadEvent: !!stateStored?.threadHeadEventId ?
114:             room.findEventById(stateStored.threadHeadEventId) : undefined,
115:         memberInfoEvent: !!stateStored?.memberInfoEventId ?
116:             room.findEventById(stateStored.memberInfoEventId) : undefined,
117:         initialEvent: !!stateStored?.initialEventId ?
118:             room.findEventById(stateStored.initialEventId) : undefined,
119:         member: !!stateStored?.memberId ?
120:             room.getMember(stateStored.memberId) : undefined,
121:     };
122: 
123:     return { state: state, phase: panelStateStore.phase };
124: }
